/


CREATE OR REPLACE FUNCTION LGLPCM.DATEDIFF (
    P_FLAG    IN VARCHAR2,
    P_FR_DATE IN DATE,
    P_TO_DATE IN DATE
)
RETURN NUMBER IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT NUMBER;

BEGIN
    IF P_FLAG = 'SECOND' THEN
        V_RESULT := (P_TO_DATE - P_FR_DATE) * 24 * 60 * 60;
    ELSE
        V_RESULT := (P_TO_DATE - P_FR_DATE) ;
    END IF;

    IF V_RESULT IS NULL THEN
        V_RESULT := 0;
    END IF;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN 0;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_APV_PROCESS (
    P_UID IN NUMBER
)
RETURN NUMBER IS
/******************************************************************************************
 * @author  : PYB
 * @date    : 2020-07-22
 * @summary : 결재 진행현황
 * @return  : 업무협조전 식별번호
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT  NUMBER(10);
        V_STATUS  VARCHAR2(75);
        V_ALL_CNT NUMBER(10);
        V_CFM_CNT NUMBER(10);

BEGIN
    BEGIN
        SELECT STATUS
        INTO   V_STATUS
        FROM   SY_APV
        WHERE  APV_UID = P_UID;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            V_STATUS := NULL;
        WHEN TOO_MANY_ROWS THEN
            V_STATUS := NULL;
        WHEN OTHERS THEN
            V_STATUS := NULL;
    END;


    IF V_STATUS IN ('ENT', 'CAN') THEN
        V_RESULT := 0;

    ELSIF V_STATUS IN ('RJT','CFM') THEN
        V_RESULT := 100;

    ELSIF V_STATUS IN ('ING') THEN
        BEGIN
            SELECT COUNT(1)
            INTO V_ALL_CNT
            FROM SY_APV_LINE
            WHERE  APV_UID = P_UID
              AND APPR_LINE_TYPE_CODE = '200'
              AND ACTV_FLAG = 'Y';
        EXCEPTION
            WHEN OTHERS THEN
                V_ALL_CNT := 0;
        END;


        BEGIN
            SELECT COUNT(1)
            INTO V_CFM_CNT
            FROM SY_APV_LINE
            WHERE  APV_UID = P_UID
              AND APPR_LINE_TYPE_CODE = '200'
              AND STATUS = 'CFM'
              AND ACTV_FLAG = 'Y';
        EXCEPTION
            WHEN OTHERS THEN
                V_CFM_CNT := 0;
        END;


        --V_RESULT := UTILS.CONVERT_TO_NUMBER((UTILS.CONVERT_TO_NUMBER(V_CFM_CNT,5,2) / UTILS.CONVERT_TO_NUMBER(V_ALL_CNT,5,2) * 100),10,0);
        IF V_ALL_CNT > 0 THEN
            V_RESULT := TRUNC(V_CFM_CNT / V_ALL_CNT * 100);
        ELSE
            V_RESULT := 0;
        END IF;

    END IF;

    IF V_RESULT IS NULL THEN
        V_RESULT := 0 ;
    END IF;

    RETURN V_RESULT;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CALC_WORKINGDAY_CNT(
    P_STD_DATE       IN DATE     -- 기준일자
   ,P_LEAD_TIME      IN NUMBER   -- 입고소요일자 
)
RETURN NUMBER IS
/******************************************************************************************
 * @author  : sonyh
 * @date    : 2025-12-01
 * @summary : 휴일, LEAD_TIME 을 계산한 Working Day를 가져온다
 * @return  :
 ******************************************************************************************/
    V_DATE        DATE   := P_STD_DATE;
    V_LEAD_TIME   NUMBER := P_LEAD_TIME; -- 리드타임
    V_COUNT       NUMBER := 0;   -- 실제 워킹데이 카운트
    V_TOTAL_DAYS  NUMBER := 0;   -- 총 소요일수(주말/휴일 포함)

    -- 공휴일을 DATE 타입으로 담음
    TYPE T_HOLIDAY IS TABLE OF DATE;   
    HOLIDAY_LIST T_HOLIDAY;

BEGIN
    -- 1. 공휴일을 한 번에 배열로 가져오기
    SELECT TO_DATE(SC.CODE, 'YYYYMMDD') -- DATE형식으로 변환
      BULK COLLECT INTO HOLIDAY_LIST
      FROM SY_CM_CODE SC
     WHERE SC.STATUS = 'Y'
       AND SC.CLASS_CODE = 'UHOLIDAY' -- 휴일관리 (도급,일반 공통)
       -- 코드 유효성
       AND REGEXP_LIKE(SC.CODE, '^[0-9]{8}$') -- 8자리 숫자만 필터링
       AND TO_DATE(SC.CODE, 'YYYYMMDD') IS NOT NULL -- 변환 가능한 날짜만 필터링
       AND TO_DATE(SC.CODE, 'YYYYMMDD') >= TRUNC(P_STD_DATE) -- 기준일자 이후만 가져오기 , 시분초관련 자르기 위해서 TRUNC 처리함
	;

    -- 2. LEAD_TIME이 NULL 또는 0인 경우 처리
    IF V_LEAD_TIME IS NULL OR V_LEAD_TIME = 0 THEN
        -- 옵션 1: 기본값 3일로 계산
        V_LEAD_TIME := 3;

        -- 옵션 2: NULL 반환
        -- RETURN NULL;
    END IF;


    -- 워킹데이 계산 루프
    -- 리드타임에 도달할때까지
    WHILE V_COUNT < V_LEAD_TIME LOOP
	    -- 1. 날짜 증가
        V_DATE := V_DATE + 1; 
        -- 2. 총 날짜 cnt 증가
        V_TOTAL_DAYS := V_TOTAL_DAYS + 1;

        -- 3. 체크
        -- 주말 체크
        -- 주말일 경우 건너뛰기
        IF TO_CHAR(V_DATE, 'DY', 'NLS_DATE_LANGUAGE=AMERICAN') IN ('SAT','SUN') THEN
            CONTINUE;
        END IF;

        -- 공휴일 체크 
        -- 현재날짜가 HOLIDAY_LIST에 존재하면 건너뛰기
		IF V_DATE MEMBER OF HOLIDAY_LIST THEN
		    CONTINUE;
		END IF;

        -- 워킹데이 카운트 증가
        V_COUNT := V_COUNT + 1;
    END LOOP;

    -- 결과 반환 (총 소요일수(주말/휴일 포함) 리턴)
	RETURN V_TOTAL_DAYS;  

EXCEPTION WHEN OTHERS THEN
    RETURN NULL;
END;
/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CALC_WORKINGDAY_DATE(
    P_STD_DATE       IN DATE     -- 기준일자
   ,P_LEAD_TIME      IN NUMBER   -- 입고소요일자 
)
RETURN DATE IS
/******************************************************************************************
 * @author  : sonyh
 * @date    : 2025-12-01
 * @summary : 휴일, LEAD_TIME 을 계산한 Working Day를 가져온다
 * @return  :
 ******************************************************************************************/
    V_DATE        DATE   := P_STD_DATE;
    V_LEAD_TIME   NUMBER := P_LEAD_TIME; -- 리드타임
    V_COUNT       NUMBER := 0;   -- 실제 워킹데이 카운트
    V_TOTAL_DAYS  NUMBER := 0;   -- 총 소요일수(주말/휴일 포함)
    V_MULTIPL_BY  NUMBER := 0;   -- P_LEAD_TIME 리드타임이 양수+ , 음수- 처리 
    
        
    -- 공휴일을 DATE 타입으로 담음
    TYPE T_HOLIDAY IS TABLE OF DATE;   
    HOLIDAY_LIST T_HOLIDAY;

BEGIN
    -- 1. 공휴일을 한 번에 배열로 가져오기
    SELECT TO_DATE(SC.CODE, 'YYYYMMDD') -- DATE형식으로 변환
      BULK COLLECT INTO HOLIDAY_LIST
      FROM SY_CM_CODE SC
     WHERE SC.STATUS = 'Y'
       AND SC.CLASS_CODE = 'UHOLIDAY' -- 휴일관리 (도급,일반 공통)
       -- 코드 유효성
       AND REGEXP_LIKE(SC.CODE, '^[0-9]{8}$') -- 8자리 숫자만 필터링
       AND TO_DATE(SC.CODE, 'YYYYMMDD') IS NOT NULL -- 변환 가능한 날짜만 필터링
       AND TO_DATE(SC.CODE, 'YYYYMMDD') >= TRUNC(ADD_MONTHS(SYSDATE, -12), 'YYYY') -- 작년 부터기준일자 모두
	;

    -- 2. LEAD_TIME이 NULL 또는 0인 경우 처리
    IF V_LEAD_TIME IS NULL OR V_LEAD_TIME = 0 THEN
        -- 옵션 1: 기본값 3일로 계산
           V_LEAD_TIME := 3;
        
        -- 옵션 2: NULL 반환
        -- RETURN NULL;
        
        -- 옵션 3: 오늘 날짜 반환
        --  RETURN NVL(TRUNC(SYSDATE), NULL);
    END IF;

    
    -- LEAD_TIME 방향성 설정
    IF V_LEAD_TIME > 0 THEN
        V_MULTIPL_BY := 1;   -- 앞으로(+)
    ELSIF V_LEAD_TIME < 0 THEN
        V_MULTIPL_BY := -1;  -- 뒤로(-)
    ELSE
        RETURN NVL(TRUNC(SYSDATE), NULL);
    END IF;
    
    -- 워킹데이 계산 루프
    -- 리드타임에 도달할때까지
    WHILE V_COUNT <> V_LEAD_TIME LOOP
	    -- 1. 날짜 증가
        V_DATE := V_DATE + V_MULTIPL_BY; 
        -- 2. 총 날짜 cnt 증가
        V_TOTAL_DAYS := V_TOTAL_DAYS + V_MULTIPL_BY;

        -- 3. 체크
        -- 주말 체크
        -- 주말일 경우 건너뛰기
        IF TO_CHAR(V_DATE, 'DY', 'NLS_DATE_LANGUAGE=AMERICAN') IN ('SAT','SUN') THEN
            CONTINUE;
        END IF;

        -- 공휴일 체크 
        -- 현재날짜가 HOLIDAY_LIST에 존재하면 건너뛰기
		IF V_DATE MEMBER OF HOLIDAY_LIST THEN
		    CONTINUE;
		END IF;

        -- 워킹데이 카운트 증가
        V_COUNT := V_COUNT + V_MULTIPL_BY;
    END LOOP;

    -- 결과 반환 (최종 날짜 리턴)
	RETURN NVL(TRUNC(V_DATE), NULL);  

EXCEPTION WHEN OTHERS THEN
    RETURN NULL;
END;
/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_ATTACH_FILE_COUNT (
        P_DOC_NAME IN VARCHAR2,
        P_DOC_UID   IN NUMBER,
        P_FILE_TYPE IN VARCHAR2 DEFAULT NULL

    ) RETURN VARCHAR2 IS
    /******************************************************************************************
     * @author  :
     * @date    : 2009-04-22
     * @summary : 첨부파일 개수를 리턴
     * @return  :
     **********************************************************************************************/

    V_COUNT         NUMBER;

    BEGIN
       IF P_FILE_TYPE IS NULL THEN

        BEGIN
            SELECT COUNT(1)
            INTO   V_COUNT
            FROM   SY_DOC_ATTACH
            WHERE  DOC_NAME = P_DOC_NAME
              AND  DOC_UID  = P_DOC_UID
              AND  ACTV_FLAG = 'Y';
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                V_COUNT := 0;
            WHEN OTHERS THEN
                V_COUNT := 0;
        END;

       ELSE
         BEGIN
            SELECT COUNT(1)
            INTO   V_COUNT
            FROM   SY_DOC_ATTACH
            WHERE  DOC_NAME  = P_DOC_NAME
              AND  DOC_UID   = P_DOC_UID
              AND  FILE_TYPE_CODE = P_FILE_TYPE
              AND  ACTV_FLAG = 'Y';
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                V_COUNT := 0;
            WHEN OTHERS THEN
                V_COUNT := 0;
        END;


       END IF;

       RETURN V_COUNT;
    END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_CASCADE_CODE (
    P_CLIENT_CODE  IN VARCHAR2,
    P_COMPANY_CODE IN VARCHAR2,
    P_CLASS_CODE   IN VARCHAR2,
    P_CODE         IN VARCHAR2,
    P_LANGUAGE     IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary : 공통코드 순차 조회 회사 -> 그룹 -> 시스템
 * @return  : 공통코드값
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(300);
        V_SQL    VARCHAR2(300);

BEGIN
    -- 회사레벨 코드 조회
    BEGIN
        SELECT CASE WHEN CCL.NAME IS NULL THEN CD.NAME
                    ELSE CCL.NAME END
                INTO V_RESULT
        FROM SY_CM_CLASS CL
        JOIN SY_CM_CODE CD ON (CD.CLASS_CODE = CL.CLASS_CODE
                           AND CD.CLIENT_CODE = CL.CLIENT_CODE
                           AND CD.COMPANY_CODE = CL.COMPANY_CODE
                           AND CD.STATUS = 'Y')
        LEFT OUTER JOIN SY_CM_CODE_LANG CCL ON (CCL.CLASS_CODE     = CD.CLASS_CODE
                                            AND CCL.CLIENT_CODE    = CD.CLIENT_CODE
                                            AND CCL.COMPANY_CODE   = CD.COMPANY_CODE
                                            AND CCL.CODE = CD.CODE
                                            AND CCL.LANGUAGE_CODE = UPPER(P_LANGUAGE)
                                            AND CCL.CLASS_TYPE_CODE = CD.CLASS_TYPE_CODE
                                            )
        WHERE CL.CLIENT_CODE = P_CLIENT_CODE
        AND CL.COMPANY_CODE = P_COMPANY_CODE
        AND CL.CLASS_TYPE_CODE = 'C'
        AND CL.CLASS_CODE = P_CLASS_CODE
        AND CD.CODE = P_CODE
        AND CL.STATUS = 'Y';

    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := null;
        WHEN OTHERS THEN
        V_RESULT := NULL; -- 또는 로그 기록, 기본값 설정 등
    END;

    IF V_RESULT IS NOT NULL THEN
        RETURN V_RESULT;
    END IF;


    -- 그룹레벨 코드 조회
    BEGIN
        SELECT CASE WHEN CCL.NAME IS NULL THEN CD.NAME
                    ELSE CCL.NAME END
        INTO V_RESULT
        FROM SY_CM_CLASS CL
        JOIN SY_CM_CODE CD ON (CD.CLASS_CODE = CL.CLASS_CODE
                           AND CD.CLIENT_CODE = CL.CLIENT_CODE
                           AND CD.COMPANY_CODE IS NULL
                           AND CD.STATUS = 'Y')
        LEFT OUTER JOIN SY_CM_CODE_LANG CCL ON (CCL.CLASS_CODE = CD.CLASS_CODE
                                            AND CCL.CLIENT_CODE = CD.CLIENT_CODE
                                            AND CCL.COMPANY_CODE IS NULL
                                            AND CCL.CODE = CD.CODE
                                            AND CCL.LANGUAGE_CODE = UPPER(P_LANGUAGE)
                                            AND CCL.CLASS_TYPE_CODE = CD.CLASS_TYPE_CODE
                                            )
        WHERE CL.CLIENT_CODE = P_CLIENT_CODE
        AND CL.COMPANY_CODE IS NULL
        AND CL.CLASS_TYPE_CODE = 'G'
        AND CL.CLASS_CODE = P_CLASS_CODE
        AND CD.CODE = P_CODE
        AND CL.STATUS = 'Y';

    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := null;
     WHEN OTHERS THEN
        V_RESULT := NULL; -- 또는 로그 기록, 기본값 설정 등
    END;

    IF V_RESULT IS NOT NULL THEN
        RETURN V_RESULT;
    END IF;

    -- 시스템레벨 코드 조회
    BEGIN
        SELECT CASE WHEN CCL.NAME IS NULL THEN CD.NAME
                    ELSE CCL.NAME END
        INTO V_RESULT
        FROM SY_CM_CLASS CL
        JOIN SY_CM_CODE CD ON (CD.CLASS_CODE = CL.CLASS_CODE
                           AND CD.CLIENT_CODE IS NULL
                           AND CD.COMPANY_CODE IS NULL
                           AND CD.STATUS = 'Y')
        LEFT OUTER JOIN SY_CM_CODE_LANG CCL ON (CCL.CLASS_CODE = CD.CLASS_CODE
                                            AND CCL.CLIENT_CODE IS NULL
                                            AND CCL.COMPANY_CODE IS NULL
                                            AND CCL.CODE = CD.CODE
                                            AND CCL.LANGUAGE_CODE = UPPER(P_LANGUAGE)
                                            AND CCL.CLASS_TYPE_CODE = CD.CLASS_TYPE_CODE
                                            )
        WHERE CL.CLIENT_CODE IS NULL
        AND CL.COMPANY_CODE IS NULL
        AND CL.CLASS_TYPE_CODE = 'S'
        AND CL.CLASS_CODE = P_CLASS_CODE
        AND CD.CODE = P_CODE
        AND CL.STATUS = 'Y';

    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := null;
     WHEN OTHERS THEN
        V_RESULT := NULL; -- 또는 로그 기록, 기본값 설정 등
    END;

    IF V_RESULT IS NULL THEN
        V_RESULT := '';
    END IF;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_COMMON_CODE (
    P_CLIENT_CODE  IN VARCHAR2,
    P_COMPANY_CODE IN VARCHAR2,
    P_CLASS_TYPE_CODE   IN VARCHAR2,
    P_CLASS_CODE   IN VARCHAR2,
    P_CODE         IN VARCHAR2,
    P_LANGUAGE     IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary : 공통코드 조회
 * @return  : 공통코드 값
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(300);
        V_SQL    VARCHAR2(300);
        V_LANG_CODE VARCHAR2(2) := SUBSTR(UPPER(P_LANGUAGE), 1, 2);

BEGIN
    IF P_CLASS_TYPE_CODE = 'G' THEN
        SELECT CASE WHEN CCL.NAME IS NULL THEN CD.NAME
                    ELSE CCL.NAME END
        INTO V_RESULT
        FROM SY_CM_CLASS CL
        JOIN SY_CM_CODE CD ON (CD.CLASS_CODE = CL.CLASS_CODE
                           AND CD.CLIENT_CODE = CL.CLIENT_CODE
                           AND CD.COMPANY_CODE IS NULL
                           AND CD.STATUS = 'Y')
        LEFT JOIN SY_CM_CODE_LANG CCL ON (CCL.CLASS_CODE = CD.CLASS_CODE
                                      AND CCL.CLIENT_CODE = CD.CLIENT_CODE
                                      AND CCL.COMPANY_CODE IS NULL
                                      AND CCL.CODE = CD.CODE
                                      AND CCL.LANGUAGE_CODE = V_LANG_CODE)
        WHERE CL.CLIENT_CODE = P_CLIENT_CODE
        AND CL.COMPANY_CODE IS NULL
        AND CL.CLASS_TYPE_CODE = 'G'
        AND CL.CLASS_CODE = P_CLASS_CODE
        AND CD.CODE = P_CODE;

    ELSIF P_CLASS_TYPE_CODE = 'C' THEN
        SELECT CASE WHEN CCL.NAME IS NULL THEN CD.NAME
                    ELSE CCL.NAME END
        INTO V_RESULT
        FROM SY_CM_CLASS CL
        JOIN SY_CM_CODE CD ON (CD.CLASS_CODE = CL.CLASS_CODE
                           AND CD.CLIENT_CODE = CL.CLIENT_CODE
                           AND CD.COMPANY_CODE = CL.COMPANY_CODE
                           AND CD.STATUS = 'Y' )
        LEFT JOIN SY_CM_CODE_LANG CCL ON (CCL.CLASS_CODE = CD.CLASS_CODE
                                      AND CCL.CLIENT_CODE = CD.CLIENT_CODE
                                      AND CCL.COMPANY_CODE = CD.COMPANY_CODE
                                      AND CCL.CODE = CD.CODE
                                      AND CCL.LANGUAGE_CODE = V_LANG_CODE)
        WHERE CL.CLIENT_CODE = P_CLIENT_CODE
        AND CL.COMPANY_CODE = P_COMPANY_CODE
        AND CL.CLASS_TYPE_CODE = 'C'
        AND CL.CLASS_CODE = P_CLASS_CODE
        AND CD.CODE = P_CODE;

    ELSIF P_CLASS_TYPE_CODE = 'S' THEN
        SELECT CASE WHEN CCL.NAME IS NULL THEN CD.NAME
                    ELSE CCL.NAME END
        INTO V_RESULT
        FROM SY_CM_CLASS CL
        JOIN SY_CM_CODE CD ON (CD.CLASS_CODE = CL.CLASS_CODE
                           AND CD.CLIENT_CODE IS NULL
                           AND CD.COMPANY_CODE IS NULL)
        LEFT JOIN SY_CM_CODE_LANG CCL ON (CCL.CLASS_CODE = CD.CLASS_CODE
                                      AND CCL.CLIENT_CODE IS NULL
                                      AND CCL.COMPANY_CODE IS NULL
                                      AND CCL.CODE = CD.CODE
                                      AND CCL.LANGUAGE_CODE = V_LANG_CODE)
        WHERE CL.CLIENT_CODE IS NULL
        AND CL.COMPANY_CODE IS NULL
        AND CL.CLASS_TYPE_CODE = 'S'
        AND CL.CLASS_CODE = P_CLASS_CODE
        AND CD.CODE = P_CODE;
    END IF;

    IF V_RESULT IS NULL THEN
        V_RESULT := '';
    END IF;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;

/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_GET_COST_DOC_INFO (
    P_PURCHASE_COST_UID IN NUMBER,
    P_TYPE              IN VARCHAR2  -- 'DOC_TYPE' 또는 'DOC_UID'
) RETURN VARCHAR2
IS
    V_COST_TYPE_CODE VARCHAR2(10);
    V_COST_DOC_UID   NUMBER;
    V_RESULT         VARCHAR2(100);
BEGIN
    -- 1. PO 매핑 확인
    BEGIN
        SELECT MAX(D.PO_D1_UID)
        INTO V_COST_DOC_UID
        FROM MM_PO_D1 D
        WHERE D.ACTV_FLAG = 'Y'
          AND D.PURCHASE_COST_UID = P_PURCHASE_COST_UID;

        V_COST_TYPE_CODE := 'PO';

    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            V_COST_DOC_UID := NULL;
            V_COST_TYPE_CODE := NULL;
        WHEN OTHERS THEN
            V_COST_DOC_UID := NULL;
            V_COST_TYPE_CODE := NULL;
    END;

    -- 2. RX 매핑 (RQ, BD 타입 중 최신 RX_SEQ)
    IF V_COST_DOC_UID IS NULL THEN
        BEGIN
            SELECT RX_D1_UID
            INTO V_COST_DOC_UID
            FROM (
                SELECT D.RX_D1_UID
                FROM MM_RX_D1 D
                JOIN MM_RX_H H ON D.RX_H_UID = H.RX_H_UID
                WHERE D.ACTV_FLAG = 'Y'
                  AND H.ACTV_FLAG = 'Y'
                  AND H.RFX_TYPE_CODE IN ('RQ', 'BD')
                  AND D.PURCHASE_COST_UID = P_PURCHASE_COST_UID
                ORDER BY H.RX_SEQ DESC
            )
            WHERE ROWNUM = 1;

            V_COST_TYPE_CODE := 'RX';

        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                V_COST_DOC_UID := NULL;
                V_COST_TYPE_CODE := NULL;
            WHEN OTHERS THEN
                V_COST_DOC_UID := NULL;
                V_COST_TYPE_CODE := NULL;
        END;
    END IF;

    -- 3. RP 매핑 확인
    IF V_COST_DOC_UID IS NULL THEN
        BEGIN
            SELECT MAX(D.RX_D1_UID)
            INTO V_COST_DOC_UID
            FROM MM_RX_D1 D
            JOIN MM_RX_H H ON D.RX_H_UID = H.RX_H_UID
            WHERE D.ACTV_FLAG = 'Y'
              AND H.ACTV_FLAG = 'Y'
              AND H.RFX_TYPE_CODE = 'RP'
              AND D.PURCHASE_COST_UID = P_PURCHASE_COST_UID;

           IF V_COST_DOC_UID IS NOT NULL THEN
                V_COST_TYPE_CODE := 'RP';
            ELSE
                V_COST_TYPE_CODE := NULL;
            END IF;


        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                V_COST_DOC_UID := NULL;
                V_COST_TYPE_CODE := NULL;
            WHEN OTHERS THEN
                V_COST_DOC_UID := NULL;
                V_COST_TYPE_CODE := NULL;
        END;
    END IF;

    -- 결과 반환
    IF UPPER(P_TYPE) = 'DOC_TYPE' THEN
        V_RESULT := NVL(V_COST_TYPE_CODE, NULL);
    ELSE
        V_RESULT := NVL(TO_CHAR(V_COST_DOC_UID), NULL);
    END IF;

    RETURN V_RESULT;

EXCEPTION
    WHEN OTHERS THEN
        RETURN NULL;
END;

/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_ITEM_CLASS_PATH (
    P_CLIENT_CODE     IN VARCHAR2,
    P_ITEM_CLASS_CODE IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(300);

BEGIN
    BEGIN
        SELECT LISTAGG(ITEM_CLASS_NAME, ' > ') WITHIN GROUP (ORDER BY LEVEL DESC) AS ITEM_CLASS_NAME
        INTO   V_RESULT
        FROM   MD_ITEM_CLASS A
        WHERE  A.CLIENT_CODE = P_CLIENT_CODE
        AND    A.STATUS = 'Y'
        START WITH ITEM_CLASS_CODE = P_ITEM_CLASS_CODE AND  A.CLIENT_CODE = P_CLIENT_CODE
        CONNECT BY A.PARENT_CODE || '/' || A.ITEM_CLASS_CODE = PRIOR  A.PARENT_CODE AND  A.CLIENT_CODE = P_CLIENT_CODE;

   EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := '';
   WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

   RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_LABEL (
    P_CODE IN VARCHAR2,
    P_LANG IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(4000);

BEGIN
    BEGIN
        SELECT DESCRIPTION
        INTO V_RESULT
        FROM SY_LABEL
        WHERE UPPER(LANGUAGE_CODE) = UPPER(SUBSTR(P_LANG, 1, 2))
          AND CODE = P_CODE
          AND STATUS = 'Y';
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            V_RESULT := NULL; -- 또는 기본값 설정
        WHEN TOO_MANY_ROWS THEN
            V_RESULT := NULL; -- 또는 로깅/처리
        WHEN OTHERS THEN
            V_RESULT := NULL; -- 예외 메시지 로깅 가능
    END;

    IF V_RESULT IS NULL THEN
        V_RESULT := '';
    END IF;

    RETURN V_RESULT;
END;
END;


/


