CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_NUMBER_VALUE_COMPANY (
    P_CLIENT_CODE  IN VARCHAR2,
    P_COMPANY_CODE IN VARCHAR2,
    P_VALUE        IN NUMBER,
    P_TYPE         IN VARCHAR2,
    P_CURRENCY     IN VARCHAR2 DEFAULT 'KRW'
)
RETURN NUMBER IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
    숫자타입 필드의 소수점 처리(회사 기준)
    전처리 : 프로시저 에서 호출 시 FN_VALIDATION_NUMBER_FORMAT 로 유효성체크
    P_CLIENT_CODE  : Data Owner 그룹코드
    P_COMPANY_CODE : Data Owner 회사코드
    P_VALUE        : 소수점 처리가 필요한 Number값
    P_TYPE         : 소수점 처리 유형(PRICE,AMOUNT,QUANTITY,WEIGHT,CBM ...)
    P_CURRENCY     : 화폐단위
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_SCALE        NUMBER;          -- 소수점 자리수
        V_CURR_SCALE   NUMBER;          -- 통화별 소숫점 자리수
        V_SCALE_TYPE   VARCHAR2(100);   -- 소수점 이하 자리수 처리
        V_RTN_VALUE    NUMBER(27,9);    -- 리턴값
        V_CORRECTION   NUMBER(10,9);    -- 보정값(올림처리시 사용)
        V_UNIT_CODE    VARCHAR2(10);    -- 포멧코드
        V_DETAIL_CODE  VARCHAR2(10);    -- 포멧코드
        V_DETAIL_VALUE VARCHAR2(150);   -- 포멧값
        V_CLASS_CODE   VARCHAR2(10);    -- 포멧 타입

        CURSOR FORMATTER IS
            SELECT NVL(UNIT_CODE, 'BASE') UNIT_CODE,
                   DETAIL_CODE,
                   DETAIL_VALUE
            FROM   (SELECT FD.DETAIL_CODE,
                           FD.DETAIL_VALUE,
                           FD.UNIT_CODE,
                           RANK() OVER (PARTITION BY FMT.FORMAT_CODE, FD.CLASS_CODE, FD.DETAIL_CODE ORDER BY FMT.CLASS_CODE ASC, FD.CLASS_CODE DESC) LVL
                    FROM   SY_FORMAT FMT JOIN SY_FORMAT_DETAIL FD ON (((FMT.CLIENT_CODE IS NULL
                                                                        AND FD.CLIENT_CODE IS NULL
                                                                        AND FMT.COMPANY_CODE IS NULL
                                                                        AND FD.COMPANY_CODE IS NULL
                                                                        AND FMT.FORMAT_CODE = FD.FORMAT_CODE)
                                                                    OR (FMT.CLIENT_CODE IS NULL
                                                                        AND FD.CLIENT_CODE IS NULL
                                                                        AND FMT.COMPANY_CODE = FD.COMPANY_CODE
                                                                        AND FMT.FORMAT_CODE = FD.FORMAT_CODE)
                                                                    OR (FMT.CLIENT_CODE = FD.CLIENT_CODE
                                                                        AND FMT.COMPANY_CODE = FD.COMPANY_CODE
                                                                        AND FMT.FORMAT_CODE = FD.FORMAT_CODE))
                                                                   AND FD.ACTV_FLAG = 'Y')
                    WHERE  FMT.ACTV_FLAG = 'Y'
                    AND    (FMT.CLASS_CODE = 'S' OR (FMT.CLASS_CODE = 'G' AND FMT.CLIENT_CODE = P_CLIENT_CODE)
                            OR (FMT.CLASS_CODE = 'C' AND FMT.CLIENT_CODE = P_CLIENT_CODE AND FMT.COMPANY_CODE = P_COMPANY_CODE))
                    AND    FMT.FORMAT_CODE = V_CLASS_CODE
                    AND    FD.DETAIL_CODE IN ('mode', 'pointStr')
                    AND    (FD.UNIT_CODE IS NULL OR FD.UNIT_CODE = P_CURRENCY)
                   ) A
            WHERE  LVL = 1;

BEGIN

    IF 1 = 1 THEN
        RETURN P_VALUE;
    END IF;


    -- TO-DO : 소스 변경후 추후 삭제
    IF P_TYPE = 'PRICE' THEN
        V_CLASS_CODE := 'price';

    ELSIF P_TYPE = 'AMOUNT' THEN
        V_CLASS_CODE := 'amt';

    ELSIF P_TYPE = 'QUANTITY' THEN
        V_CLASS_CODE := 'qty';

    ELSIF P_TYPE = 'WEIGHT' THEN
        V_CLASS_CODE := 'weight';

    ELSIF P_TYPE = 'CBM' THEN
        V_CLASS_CODE := 'cbm';

    ELSE
        V_CLASS_CODE := P_TYPE ;
    END IF;

    OPEN FORMATTER;
    FETCH FORMATTER INTO V_UNIT_CODE, V_DETAIL_CODE, V_DETAIL_VALUE;

    WHILE FORMATTER%FOUND LOOP
        -- 전역설정
        IF V_UNIT_CODE = 'BASE' THEN
            IF V_DETAIL_CODE = 'pointStr' THEN
                --V_SCALE := UTILS.CONVERT_TO_NUMBER(V_DETAIL_VALUE,18) ;
                V_SCALE := TO_NUMBER(V_DETAIL_VALUE);

            ELSIF V_DETAIL_CODE = 'mode' THEN
                V_SCALE_TYPE := V_DETAIL_VALUE;
            END IF;

        --통화설정
        ELSE
            IF V_DETAIL_CODE = 'pointStr' THEN
                --V_CURR_SCALE := UTILS.CONVERT_TO_NUMBER(V_DETAIL_VALUE,18);
                V_CURR_SCALE := TO_NUMBER(V_DETAIL_VALUE);
            END IF;
        END IF;

        FETCH FORMATTER INTO V_UNIT_CODE,V_DETAIL_CODE,V_DETAIL_VALUE;
    END LOOP;
    CLOSE FORMATTER;

    /*======================================================
      ※ 소수점을 사용하지 않는 통화처리
     =======================================================*/
    IF V_CLASS_CODE = 'amt' AND V_CURR_SCALE IS NOT NULL THEN
        V_SCALE := V_CURR_SCALE;
    END IF;

    IF V_SCALE IS NULL AND V_SCALE_TYPE IS NULL THEN
        RETURN -1;
    END IF;

    /*======================================================
      ※ 올림작업을 위한 보정값 생성
     =======================================================*/
    --V_CORRECTION := '0.' || LPAD('', 9 - LENGTH(UTILS.CONVERT_TO_VARCHAR2((V_SCALE + 1), 30)), '0') || UTILS.CONVERT_TO_VARCHAR2((V_SCALE + 1), 30);
    --V_CORRECTION := '0.' || LPAD('', 9 - LENGTH(TO_CHAR(V_SCALE + 1))) || TO_CHAR(V_SCALE + 1);

    -- 소수점 처리
    IF V_SCALE_TYPE = 'ROUND' THEN
        --V_RTN_VALUE := utils.round_(P_VALUE, V_SCALE);
        V_RTN_VALUE := ROUND(P_VALUE, V_SCALE);

    ELSIF V_SCALE_TYPE = 'CEIL' THEN
        --V_RTN_VALUE := utils.round_(P_VALUE + V_CORRECTION, V_SCALE, -1);
        V_RTN_VALUE := CEIL(P_VALUE*POWER(10, V_SCALE))/POWER(10, V_SCALE);

    ELSIF V_SCALE_TYPE = 'FLOOR' THEN
        --V_RTN_VALUE := utils.round_(P_VALUE, V_SCALE, -1);
        V_RTN_VALUE := TRUNC(P_VALUE, V_SCALE);

    ELSE
        RETURN -1;
    END IF;

    RETURN V_RTN_VALUE;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_OPER_UNIT_NAME (
    P_CLIENT_CODE IN VARCHAR2,
    P_COMPANY_CODE IN VARCHAR2,
