CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_ORG_FULL_PATH_NAME(
  P_CLIENT_CODE VARCHAR2,
  P_COMPANY_CODE VARCHAR2,
  P_CLASS_CODE  VARCHAR2
)
RETURN VARCHAR2
AS
  v_input_code VARCHAR2(4000) :=  P_CLASS_CODE;
  v_result_name VARCHAR2(4000) := NULL;
  v_delimiter CHAR(1) := '/';
  v_pos NUMBER;
  v_current_code VARCHAR2(4000);
BEGIN
  -- 초기값 설정
  v_result_name := NULL;



  IF LENGTH(v_input_code) > 1 then
    v_input_code := substr(v_input_code, 2);
  end IF;

  -- '/'로 코드 분리 및 명칭 조회
  WHILE INSTR(v_input_code, v_delimiter) > 0
  LOOP
    -- '/'를 찾으면 앞의 코드를 추출하여 명칭을 조회
    v_pos := INSTR(v_input_code, v_delimiter);
    v_current_code := SUBSTR(v_input_code, 1, v_pos - 1);

    BEGIN
      SELECT COALESCE(v_result_name || ' > ', '') || ORG_NAME
      INTO v_result_name
      FROM sy_org
      WHERE CLIENT_CODE = P_CLIENT_CODE
        AND COMPANY_CODE = P_COMPANY_CODE
        AND ORG_CODE = v_current_code;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        NULL; -- OR: v_result_name := v_result_name; -- 유지
      WHEN TOO_MANY_ROWS THEN
        NULL; -- OR: v_result_name := v_result_name || ' > [중복]';
      WHEN OTHERS THEN
        NULL;
    END;


    -- 남은 코드 업데이트
    v_input_code := SUBSTR(v_input_code, v_pos + 1);
  END LOOP;

  -- 나머지 코드에 해당하는 명칭 추가
  IF v_input_code IS NOT NULL
  THEN
    BEGIN
      SELECT COALESCE(v_result_name || ' > ', '') || ORG_NAME
      INTO v_result_name
      FROM sy_org
      WHERE CLIENT_CODE = P_CLIENT_CODE
        AND COMPANY_CODE = P_COMPANY_CODE
        AND ORG_CODE = v_input_code;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        NULL;
      WHEN TOO_MANY_ROWS THEN
        NULL;
      WHEN OTHERS THEN
        NULL;
    END;

  END IF;

  IF INSTR(v_result_name, ' > ') = 1 THEN
    v_result_name := substr(v_result_name, 4);
  END IF;



  RETURN v_result_name;
END;


/


