CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_SOURCING_GROUP_PATH (
    P_CLIENT_CODE     IN VARCHAR2,
    P_CLASS_CODE      IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(300);

BEGIN
    BEGIN
        SELECT LISTAGG(CLASS_NAME, ' > ') WITHIN GROUP (ORDER BY LEVEL DESC) AS CLASS_NAME
        INTO   V_RESULT
        FROM   MD_SOURCING_GROUP A
        WHERE  A.CLIENT_CODE = P_CLIENT_CODE
        AND    A.STATUS = 'Y'
        AND    A.CLASS_LEVEL != 0
        START WITH CLASS_CODE = P_CLASS_CODE AND  A.CLIENT_CODE =  P_CLIENT_CODE
        CONNECT BY PRIOR  A.PARENT_CLASS_CODE = A.PARENT_CLASS_CODE || '/' || A.CLASS_CODE   AND  A.CLIENT_CODE =  P_CLIENT_CODE;

   EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := '';
   WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

   RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_STATUS (
    P_CLIENT_CODE   IN VARCHAR2,
    P_ACTIVITY_CODE IN VARCHAR2,
    P_STATUS_CODE   IN VARCHAR2,
    P_LANGUAGE      IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT   VARCHAR2(150);
        V_LANGUAGE VARCHAR2(10);

BEGIN

    V_LANGUAGE := P_LANGUAGE;


    IF LENGTH(V_LANGUAGE) > 2 THEN
       V_LANGUAGE := SUBSTR(V_LANGUAGE,1,2);
    END IF;


    SELECT CASE NVL(UPPER(V_LANGUAGE), 'KO') WHEN 'KO' THEN ACTIVITY_STT_NAME
                                             ELSE ACTIVITY_STT_NAME_EN END
    INTO   V_RESULT
    FROM   SY_PROCESS_ACTIVITY_STT
    WHERE  CLIENT_CODE = P_CLIENT_CODE
    AND    ACTIVITY_STT_CODE = P_STATUS_CODE
    AND    ACTIVITY_CODE = P_ACTIVITY_CODE
    AND    STATUS = 'Y';

    IF V_RESULT IS NULL THEN
        V_RESULT := '';
    END IF;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_DECRYPT (
    P_ENCRYPTED_STR IN VARCHAR2,
    P_ENC_TYPE      IN VARCHAR2 DEFAULT 'AES'
)
RETURN VARCHAR2
IS
/******************************************************************************************
 * @author  :
 * @date    : 2022-04-08
 * @summary : 암호화 문자열을 복호화한다.
 ******************************************************************************************/
BEGIN
    DECLARE
        V_ENCRYPTION_TYPE CONSTANT PLS_INTEGER := DBMS_CRYPTO.ENCRYPT_AES256 + DBMS_CRYPTO.CHAIN_CBC + DBMS_CRYPTO.PAD_PKCS5;

        V_DECRYPTED_RAW   RAW(2000);
        V_DECRYPTED_STR   VARCHAR2(2000);

        V_KEY_STR         VARCHAR2(32) := 'matrix2b*msuite4_20220408_122400';
        V_KEY_BYTES_RAW   RAW(32);

BEGIN
    IF P_ENCRYPTED_STR = NULL OR P_ENCRYPTED_STR = '' THEN
        RETURN '';
    END IF;

    IF UPPER(P_ENC_TYPE) = 'AES' THEN
        V_DECRYPTED_RAW := DBMS_CRYPTO.DECRYPT(
            src => UTL_ENCODE.BASE64_DECODE(UTL_RAW.CAST_TO_RAW(P_ENCRYPTED_STR)),
            typ => V_ENCRYPTION_TYPE,
            key => UTL_I18N.STRING_TO_RAW(V_KEY_STR, 'AL32UTF8'),
            iv  => UTL_I18N.STRING_TO_RAW(SUBSTR(V_KEY_STR, 1, 16), 'AL32UTF8')
        );

        V_DECRYPTED_STR := UTL_I18N.RAW_TO_CHAR(V_DECRYPTED_RAW, 'AL32UTF8');
    ELSE
        V_DECRYPTED_STR := P_ENCRYPTED_STR;
    END IF;

    RETURN V_DECRYPTED_STR;

EXCEPTION WHEN OTHERS THEN
    RETURN P_ENCRYPTED_STR;
END;
END;
/


CREATE OR REPLACE FUNCTION LGLPCM.FN_ENCRYPT (
    P_PLAIN_STR IN VARCHAR2,
    P_ENC_TYPE  IN VARCHAR2 DEFAULT 'AES'
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  :
 * @date    : 2022-04-08
 * @summary : 평문 문자열을 암호화한다.
 ******************************************************************************************/
BEGIN
    DECLARE
        V_ENCRYPTION_TYPE CONSTANT PLS_INTEGER := DBMS_CRYPTO.ENCRYPT_AES256 + DBMS_CRYPTO.CHAIN_CBC + DBMS_CRYPTO.PAD_PKCS5;

        V_ENCRYPTED_RAW   RAW(2000);
        V_ENCRYPTED_STR   VARCHAR2(2000);

        V_KEY_STR         VARCHAR2(32) := 'matrix2b*msuite4_20220408_122400';
        V_KEY_BYTES_RAW   RAW(32);

BEGIN
    IF P_PLAIN_STR = NULL OR P_PLAIN_STR = '' THEN
        RETURN '';
    END IF;

    IF UPPER(P_ENC_TYPE) = 'AES' THEN
        V_ENCRYPTED_RAW := DBMS_CRYPTO.ENCRYPT(
            src => UTL_I18N.STRING_TO_RAW(P_PLAIN_STR, 'AL32UTF8'),
            typ => V_ENCRYPTION_TYPE,
            key => UTL_I18N.STRING_TO_RAW(V_KEY_STR, 'AL32UTF8'),
            iv  => UTL_I18N.STRING_TO_RAW(SUBSTR(V_KEY_STR, 1, 16), 'AL32UTF8')
        );

        V_ENCRYPTED_STR := UTL_RAW.CAST_TO_VARCHAR2(UTL_ENCODE.BASE64_ENCODE(V_ENCRYPTED_RAW));
    ELSE
        V_ENCRYPTED_STR := P_PLAIN_STR;
    END IF;

    RETURN V_ENCRYPTED_STR;

EXCEPTION WHEN OTHERS THEN
    RETURN P_PLAIN_STR;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_GET_APV_INFO (
    P_INFO_TYPE    IN VARCHAR2,
    P_DOC_NAME     IN VARCHAR2,
    P_DOC_UID      IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    : 2022-1003
 * @summary :
 * @param   : P_INFO_TYPE : UID- APV 의 UID리턴, STATUS - STATUS코드 리턴, NO - NO 리턴
 *            P_DOC_NAME  : 문서코드
 *            P_DOC_UID   : 결재올린 문서의 UID
 * @return  : 결재상태코드 및 결재문서 UID
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT         VARCHAR2(150):='';
        V_APV_STATUS     VARCHAR2(150);
        V_APPR_NO        VARCHAR2(150);
        V_APV_UID        NUMBER;
        V_CLIENT_CODE    VARCHAR2(10);
		V_APPR_END_DATE  DATE;
		V_APPR_END_USER_NAME VARCHAR2(256);
    BEGIN

        SELECT SA.APV_UID
              ,SA.CLIENT_CODE
              ,SA.STATUS
              ,SA.APPR_NO
              ,SA.APPR_END_DATE
              ,SA.APPR_END_USER_NAME  
          INTO V_APV_UID
              ,V_CLIENT_CODE
              ,V_APV_STATUS
              ,V_APPR_NO
              ,V_APPR_END_DATE
              ,V_APPR_END_USER_NAME
          FROM SY_APV SA
         WHERE APV_UID = (SELECT MAX(A.APV_UID)
                               FROM SY_APV A
                                    INNER JOIN SY_APV_DOC B ON A.APV_UID   = B.APV_UID
                                                               AND A.ACTV_FLAG = 'Y'
                                                               AND B.ACTV_FLAG = 'Y'
                                                               AND B.DOC_NAME  = P_DOC_NAME
                                                               AND B.DOC_UID   = P_DOC_UID
                             )
        ;

        IF P_INFO_TYPE = 'UID' THEN
            V_RESULT := TO_CHAR(V_APV_UID);
        ELSIF P_INFO_TYPE = 'STATUS' THEN
            V_RESULT := V_APV_STATUS;
        ELSIF P_INFO_TYPE = 'NO' THEN
            V_RESULT := V_APPR_NO;
        ELSIF P_INFO_TYPE = 'END_DATE' THEN
	        V_RESULT := TO_CHAR(V_APPR_END_DATE, 'YYYY-MM-DD HH24:MI:SS');
        ELSIF P_INFO_TYPE = 'END_USER_NAME' THEN
	        V_RESULT := V_APPR_END_USER_NAME;
        ELSIF P_INFO_TYPE = 'END_USER_NAME_DEC' THEN
	        V_RESULT :=  FN_DECRYPT(V_APPR_END_USER_NAME, 'AES');
        ELSIF P_INFO_TYPE = 'STATUS_END_USER' THEN
	        V_RESULT := (CASE WHEN V_APV_STATUS = 'CFM' THEN FN_CO_STATUS(V_CLIENT_CODE, 'APPR_CO', V_APV_STATUS, null) ||  ' (' || FN_DECRYPT(V_APPR_END_USER_NAME, 'AES') || ')'
                             ELSE FN_CO_STATUS(V_CLIENT_CODE, 'APPR_CO', V_APV_STATUS, null)
                         END);
        ELSE
            V_RESULT := V_APV_UID;
        END IF;

        RETURN V_RESULT;

    EXCEPTION WHEN OTHERS THEN
        RETURN '';
    END;
END;
/


CREATE OR REPLACE FUNCTION LGLPCM.FN_GET_COST_SUMMARY (
    P_PURCHASE_COST_UID IN NUMBER,
    P_COST_TYPE         IN VARCHAR2,
    P_TYPE              IN VARCHAR2  -- 'COST_CNT' 또는 'COST_AMOUNT'
) RETURN NUMBER
IS
    V_COST_CNT    NUMBER := 0;
    V_COST_AMOUNT NUMBER := 0;
    V_HIS_CNT     NUMBER := 0;
BEGIN
    -- 1. 과거 테이블 조회
    BEGIN
        SELECT COUNT(*),
               NVL(SUM(NVL(PCS.ITEM_AMOUNT, 0)), 0)
             + NVL(SUM(NVL(PCS.LABOR_AMOUNT, 0)), 0)
             + NVL(SUM(NVL(PCS.SERVICE_AMOUNT, 0)), 0)
             + NVL(SUM(NVL(PCS.EQUIP_AMOUNT, 0)), 0)
             + NVL(SUM(NVL(PCS.INDIRECT_AMOUNT, 0)), 0)
             + NVL(SUM(NVL(PCS.ETC_AMOUNT, 0)), 0)
        INTO V_HIS_CNT, V_COST_AMOUNT
        FROM MD_PURCHASE_COST_SET_HIS PCS
        WHERE PCS.ACTV_FLAG = 'Y' 
          AND PCS.PURCHASE_COST_UID = P_PURCHASE_COST_UID
          AND PCS.COST_SEQ = ( SELECT MAX(HHIS.COST_SEQ)
                               FROM MD_PURCHASE_COST_SET_HIS HHIS
                               WHERE HHIS.ACTV_FLAG = 'Y'
                                 AND HHIS.PURCHASE_COST_UID = PCS.PURCHASE_COST_UID
                                 AND HHIS.COST_TYPE_CODE = P_COST_TYPE);

        V_COST_CNT := V_HIS_CNT;

    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            V_HIS_CNT := 0;
            V_COST_CNT := 0;
            V_COST_AMOUNT := 0;
        WHEN OTHERS THEN
            V_HIS_CNT := 0;
            V_COST_CNT := 0;
            V_COST_AMOUNT := 0;
    END;

    -- 2. 현재 테이블 조회 (과거 건수가 0일 경우만)
    IF V_HIS_CNT = 0 THEN
        BEGIN
            SELECT COUNT(*),
                   NVL(SUM(NVL(PCS.ITEM_AMOUNT, 0)), 0)
                 + NVL(SUM(NVL(PCS.LABOR_AMOUNT, 0)), 0)
                 + NVL(SUM(NVL(PCS.SERVICE_AMOUNT, 0)), 0)
                 + NVL(SUM(NVL(PCS.EQUIP_AMOUNT, 0)), 0)
                 + NVL(SUM(NVL(PCS.INDIRECT_AMOUNT, 0)), 0)
                 + NVL(SUM(NVL(PCS.ETC_AMOUNT, 0)), 0)
            INTO V_COST_CNT, V_COST_AMOUNT
            FROM MD_PURCHASE_COST_SET PCS
            WHERE PCS.ACTV_FLAG = 'Y' 
              AND PCS.PURCHASE_COST_UID = P_PURCHASE_COST_UID;

        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                V_COST_CNT := 0;
                V_COST_AMOUNT := 0;
            WHEN OTHERS THEN
                V_COST_CNT := 0;
                V_COST_AMOUNT := 0;
        END;
    END IF;

    -- 3. 결과 반환
    IF UPPER(P_TYPE) = 'COST_CNT' THEN
        RETURN NVL(V_COST_CNT, 0);
    ELSE
        RETURN NVL(V_COST_AMOUNT, 0);
    END IF;

EXCEPTION
    WHEN OTHERS THEN
        RETURN 0;
END;

/


CREATE OR REPLACE FUNCTION LGLPCM.FN_GET_INT_APPR_ID(
    P_DRAFTER_ID     IN VARCHAR2 -- 기안자
   ,P_APPR_DUTY_CODE IN VARCHAR2 -- 승인자 직책 (팀장(120), 센터장(130), 지점장(390) , 매니저(150) , 사무소장(440)) 
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : sonyh
 * @date    : 2025-08-01
 * @summary : 내부품의 승인자ID를 가져온다
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT     VARCHAR2(150);
        V_ORG_PATH   VARCHAR2(100);    -- 기안자 조직경로

        -- 문자열 리스트 타입
	    V_ORG_PATH_LIST  SYS.ODCIVARCHAR2LIST := SYS.ODCIVARCHAR2LIST();  -- 조직경로 
	    V_DUTY_CODE_LIST SYS.ODCIVARCHAR2LIST := SYS.ODCIVARCHAR2LIST();  -- 직책코드        

BEGIN
	
	-- 기안자의 조직경로 조회
	SELECT SO.ORG_PATH
	  INTO V_ORG_PATH
	  FROM SY_USER SU 
	       INNER JOIN SY_ORG SO ON (SU.ORG_CODE = SO.ORG_CODE AND SO.ACTV_FLAG = 'Y')
	WHERE SU.USER_ID = P_DRAFTER_ID
	  AND SU.ACTV_FLAG = 'Y'
	;
	

    -- 조직경로
    --   1 : 기안자의 조직경로 넣기
    V_ORG_PATH_LIST.EXTEND;
	V_ORG_PATH_LIST(1) := V_ORG_PATH;  
    --   2~  : LOOP 돌면서 상위 조직경로 넣기
	FOR i IN 1 .. REGEXP_COUNT(V_ORG_PATH, '/') + 1 LOOP
	    V_ORG_PATH_LIST.EXTEND;
	    V_ORG_PATH_LIST(i + 1) := SUBSTR(V_ORG_PATH, 1, INSTR(V_ORG_PATH, '/', 1, i) - 1);
	END LOOP;

    -- 직책코드
    --   1~ : LOOP 돌면서 직책코드 LIST로 넣기
    FOR i IN 1 .. REGEXP_COUNT(P_APPR_DUTY_CODE, '\|') + 1 LOOP
        V_DUTY_CODE_LIST.EXTEND;
        V_DUTY_CODE_LIST(i) := REGEXP_SUBSTR(P_APPR_DUTY_CODE, '[^|]+', 1, i);
    END LOOP;



    -- 승인자 가져오기
    --  기안자의 상위조직 모두 조회하고, 
    --  특정 직책의 정보 모두 가져온다.  ex. 팀장(120) , 센터장(130), 지점장(390) , 매니저(150) , 사무소장(440)
    SELECT APPR.USER_ID
      INTO V_RESULT
      FROM SY_USER APPR  --  승인자 정보
           JOIN SY_ORG ORG ON (APPR.CLIENT_CODE = ORG.CLIENT_CODE 
                               AND APPR.COMPANY_CODE = ORG.COMPANY_CODE 
                               AND APPR.ORG_CODE = ORG.ORG_CODE
                               AND ORG.ACTV_FLAG = 'Y')
     WHERE 1=1
       AND APPR.ACTV_FLAG = 'Y'
       AND ORG.ORG_PATH   IN (SELECT COLUMN_VALUE FROM TABLE(V_ORG_PATH_LIST))   -- 기안자의 상위 조직 모두 가져오기
       AND APPR.DUTY_CODE IN (SELECT COLUMN_VALUE FROM TABLE(V_DUTY_CODE_LIST))  -- 승인자의 직책코드 모두 가져오기
     ORDER BY ORG.ORG_PATH DESC
     FETCH FIRST 1 ROWS ONLY  -- 첫번째
    ;


       
    RETURN NVL(V_RESULT, NULL);  -- 승인자ID 리턴

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;
/


CREATE OR REPLACE FUNCTION LGLPCM.FN_GET_INT_APPR_INFO(
    P_DRAFTER_ID     IN VARCHAR2 -- 기안자
   ,P_APPR_DUTY_CODE IN VARCHAR2 -- 승인자 직책 (팀장(120), 센터장(130), 지점장(390) , 매니저(150) , 사무소장(440)) 
   ,P_TYPE_CODE      IN VARCHAR2 -- 구분코드 (USER_ID / USER_NAME)   
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : sonyh
 * @date    : 2025-08-01
 * @summary : 내부품의 승인자 정보를 가져온다.
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT     VARCHAR2(150);
        V_ORG_PATH   VARCHAR2(100);    -- 기안자 조직경로

	    V_ORG_PATH_LIST  SYS.ODCIVARCHAR2LIST := SYS.ODCIVARCHAR2LIST();  -- 조직경로 
	    V_DUTY_CODE_LIST SYS.ODCIVARCHAR2LIST := SYS.ODCIVARCHAR2LIST();  -- 직책코드

        
        V_APPR_INFO SY_USER%ROWTYPE;        -- 승인자정보 ROW Data

BEGIN
	
	-- 기안자의 조직경로 조회
	SELECT SO.ORG_PATH
	  INTO V_ORG_PATH
	  FROM SY_USER SU 
	       INNER JOIN SY_ORG SO ON (SU.ORG_CODE = SO.ORG_CODE AND SO.ACTV_FLAG = 'Y')
	WHERE SU.USER_ID = P_DRAFTER_ID
	  AND SU.ACTV_FLAG = 'Y'
	;

    -- 조직경로
    --   1 : 기안자의 조직경로 넣기
    V_ORG_PATH_LIST.EXTEND;
	V_ORG_PATH_LIST(1) := V_ORG_PATH;  
    --   2~  : LOOP 돌면서 상위 조직경로 넣기
	FOR i IN 1 .. REGEXP_COUNT(V_ORG_PATH, '/') + 1 LOOP
	    V_ORG_PATH_LIST.EXTEND;
	    V_ORG_PATH_LIST(i + 1) := SUBSTR(V_ORG_PATH, 1, INSTR(V_ORG_PATH, '/', 1, i) - 1);
	END LOOP;



    -- 직책코드
    --   1~ : LOOP 돌면서 직책코드 LIST로 넣기
    FOR i IN 1 .. REGEXP_COUNT(P_APPR_DUTY_CODE, '\|') + 1 LOOP
        V_DUTY_CODE_LIST.EXTEND;
        V_DUTY_CODE_LIST(i) := REGEXP_SUBSTR(P_APPR_DUTY_CODE, '[^|]+', 1, i);
    END LOOP;


--  FOR i IN V_ORG_PATH_LIST.FIRST .. V_ORG_PATH_LIST.LAST LOOP
--    DBMS_OUTPUT.PUT_LINE('V_ORG_PATH_LIST 값 [' || i || ']: ' || V_ORG_PATH_LIST(i));
--  END LOOP;
--
--  FOR i IN V_DUTY_CODE_LIST.FIRST .. V_DUTY_CODE_LIST.LAST LOOP
--    DBMS_OUTPUT.PUT_LINE('V_DUTY_CODE_LIST 값 [' || i || ']: ' || V_DUTY_CODE_LIST(i));
--  END LOOP;

	
    -- 승인자 가져오기
    --  기안자의 상위조직 모두 조회하고, 
    --  특정 직책의 정보 모두 가져온다.  ex. 팀장(120) , 센터장(130), 지점장(390) , 매니저(150) , 사무소장(440)
    SELECT APPR.*
      INTO V_APPR_INFO
      FROM SY_USER APPR  --  승인자 정보
           JOIN SY_ORG ORG ON (APPR.CLIENT_CODE = ORG.CLIENT_CODE 
                               AND APPR.COMPANY_CODE = ORG.COMPANY_CODE 
                               AND APPR.ORG_CODE = ORG.ORG_CODE
                               AND ORG.ACTV_FLAG = 'Y')
     WHERE 1=1
       AND APPR.ACTV_FLAG = 'Y'
       AND ORG.ORG_PATH   IN (SELECT COLUMN_VALUE FROM TABLE(V_ORG_PATH_LIST))   -- 기안자의 상위 조직 모두 가져오기
       AND APPR.DUTY_CODE IN (SELECT COLUMN_VALUE FROM TABLE(V_DUTY_CODE_LIST))  -- 승인자의 직책코드 모두 가져오기
     ORDER BY ORG.ORG_PATH DESC
     FETCH FIRST 1 ROWS ONLY  -- 첫번째
    ;



    IF P_TYPE_CODE = 'USER_ID' THEN
        V_RESULT := V_APPR_INFO.USER_ID;
    ELSIF P_TYPE_CODE = 'USER_NAME' THEN
        V_RESULT := FN_DECRYPT(V_APPR_INFO.USER_NAME, 'AES')  ;
    ELSE
        V_RESULT := NULL;
    END IF;       
       
       
    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;
/


CREATE OR REPLACE FUNCTION LGLPCM.FN_IOXO_PLANT_NAME (
    P_CLIENT_CODE  IN VARCHAR2,
    P_COMPANY_CODE IN VARCHAR2,
    P_OPER_UNIT_CODE IN VARCHAR2,
    P_OPER_UNIT_TYPE_CODE IN VARCHAR2,
    P_PLANT_CODE   IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary : P_OPER_UNIT_TYPE_CODE
 *            IO : 수입 / XO : 수출
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(75);

BEGIN

	IF P_OPER_UNIT_TYPE_CODE = 'IO' THEN

	   SELECT IP.PLANT_NAME
	     INTO V_RESULT
	     FROM SY_OPER_UNIT_IO_PLANT IP
	    WHERE IP.CLIENT_CODE = P_CLIENT_CODE
	      AND IP.COMPANY_CODE = P_COMPANY_CODE
	      AND IP.OPER_UNIT_CODE = P_OPER_UNIT_CODE
	      AND IP.OPER_UNIT_TYPE_CODE = P_OPER_UNIT_TYPE_CODE
	      AND IP.STATUS = 'Y'
	      AND IP.PLANT_CODE = P_PLANT_CODE ;

	ELSIF P_OPER_UNIT_TYPE_CODE = 'XO' THEN

	   SELECT XP.PLANT_NAME
	     INTO V_RESULT
	     FROM SY_OPER_UNIT_XO_PLANT XP
	    WHERE XP.CLIENT_CODE = P_CLIENT_CODE
	      AND XP.COMPANY_CODE = P_COMPANY_CODE
	      AND XP.OPER_UNIT_CODE = P_OPER_UNIT_CODE
	      AND XP.OPER_UNIT_TYPE_CODE = P_OPER_UNIT_TYPE_CODE
	      AND XP.STATUS = 'Y'
	      AND XP.PLANT_CODE = P_PLANT_CODE ;

	END IF;

    RETURN NVL(V_RESULT, '');

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;


/


