CREATE OR REPLACE FUNCTION LGLPCM.FN_MASK_EMAIL (
    P_STR IN VARCHAR2,
    P_MASK_YN IN VARCHAR2 DEFAULT 'N'
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    : 2025-06-26
 * @summary : 이메일 암호화 2026-01-02 마스킹해제 요청
 * @return  : 이메일: abcde11@lotte.net (계정명 4자리부터 @앞까지-4자리이하는 경우 최소1자리 이상 마스킹)
 ******************************************************************************************/
/*
BEGIN
    DECLARE
        V_RTNVALUE VARCHAR2(50);
        V_PREFIX   VARCHAR2(50);
        V_SUFFIX   VARCHAR2(50);
        V_IDX      NUMBER(10);

BEGIN
   V_IDX := INSTR(P_STR, '@');
   V_PREFIX := SUBSTR(P_STR, 0, V_IDX - 1);
   V_SUFFIX := SUBSTR(P_STR, V_IDX, LENGTH(P_STR));
   V_PREFIX := FN_MASK_NAME(V_PREFIX);

   RETURN V_PREFIX || V_SUFFIX;
END;
*/
BEGIN
   DECLARE
    V_RTNVALUE VARCHAR2(100);
    V_ACCOUNT  VARCHAR2(50);
    V_DOMAIN   VARCHAR2(50);
    V_PREFIX   VARCHAR2(50);
    V_SUFFIX   VARCHAR2(50);
      BEGIN
      
          IF NVL(UPPER(P_MASK_YN), 'N') <> 'Y' THEN
            RETURN P_STR;
          END IF;
      
          -- '@' 기준으로 계정명과 도메인 분리
          V_ACCOUNT := SUBSTR(P_STR, 1, INSTR(P_STR, '@') - 1);
          V_DOMAIN := SUBSTR(P_STR, INSTR(P_STR, '@'));

          IF LENGTH(V_ACCOUNT) <= 4 THEN
              -- 마지막 1자리 마스킹
              V_RTNVALUE := SUBSTR(V_ACCOUNT, 1, LENGTH(V_ACCOUNT) - 1) || '*' || V_DOMAIN;
          ELSE
              -- 앞 3자리 유지, 나머지 마스킹
              V_PREFIX := SUBSTR(V_ACCOUNT, 1, 3);
              V_SUFFIX := RPAD('*', LENGTH(V_ACCOUNT) - 3, '*');
              V_RTNVALUE := V_PREFIX || V_SUFFIX || V_DOMAIN;
          END IF;

          RETURN V_RTNVALUE;
      END;


END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_MASK_NAME (
    P_STR IN VARCHAR2,
    P_MASK_YN IN VARCHAR2 DEFAULT 'N'
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    : 2026-01-02
 * @summary : 마스킹해제요청(옵션으로조정)
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(300);
        V_STRLEN NUMBER(10);

BEGIN

    IF NVL(UPPER(P_MASK_YN), 'N') <> 'Y' THEN
        RETURN P_STR;
    END IF;  

    IF LENGTH(P_STR) = 2 THEN
        V_RESULT := SUBSTR(P_STR, 0, 1) || '*' ;

    ELSIF LENGTH(P_STR) >= 3 THEN
        V_STRLEN := LENGTH(P_STR) - 2 ;
        V_RESULT := SUBSTR(P_STR, 0, 1) || REPLACE(LPAD(' ', V_STRLEN, ' '), ' ', '*') || SUBSTR(P_STR, -1, 1) ;

    ELSE
        V_RESULT := P_STR ;
    END IF;

    RETURN V_RESULT;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_MASK_TEL (
    P_STR IN VARCHAR2,
    P_MASK_YN IN VARCHAR2 DEFAULT 'N'
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(300);
        V_STRLEN NUMBER(10,0);

BEGIN
  
    IF NVL(UPPER(P_MASK_YN), 'N') <> 'Y' THEN
        RETURN P_STR;
    END IF;  
    
    IF LENGTH(P_STR) > 4 THEN
        V_RESULT := SUBSTR(P_STR, 0, LENGTH(P_STR)-4) || REPLACE(LPAD(' ', 4, ' '), ' ', '*');

    ELSE
        V_RESULT := REPLACE(LPAD(' ', LENGTH(P_STR), ' '), ' ', '*');
    END IF;

    RETURN V_RESULT;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_PM_DUE_PROCESS_STATUS (
    P_PR_H_UID           IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    : 2025-03-25
 * @summary : 내역변경요청 신청 대상 - 문서상태
 * @return  : 프로세스 명  값
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(10);

BEGIN
    SELECT (CASE WHEN PR_H_UID IS NULL OR RX_H_UID IS NULL THEN STATUS
                 WHEN PO_H_UID IS NOT NULL THEN 'POE'  -- 발주
                 WHEN CT_H_UID IS NOT NULL THEN 'CTE'  -- 계약
                 WHEN RX_H_UID IS NOT NULL THEN 'RXE'  -- 견적
            END) PROGRESS_STATUS
      INTO V_RESULT
      FROM (
             SELECT PRH.STATUS, PRH.PR_H_UID, RXH.RX_H_UID, CTH.CT_H_UID, POH.PO_H_UID
                   ,ROW_NUMBER() OVER(PARTITION BY PRH.STATUS, PRH.PR_H_UID, RXH.RX_H_UID, CTH.CT_H_UID, POH.PO_H_UID
                                          ORDER BY CASE WHEN RXH.RX_H_UID IS NOT NULL THEN 0 ELSE 1 END  -- RX_H_UID가 NULL이 아닌 경우 우선
							                      ,CASE WHEN CTH.CT_H_UID IS NOT NULL THEN 0 ELSE 1 END  -- CT_H_UID가 NULL이 아닌 경우 우선
							                      ,CASE WHEN POH.PO_H_UID IS NOT NULL THEN 0 ELSE 1 END  -- PO_H_UID가 NULL이 아닌 경우 우선
							         ) AS RN
               FROM MM_PR_H PRH
                    INNER JOIN MM_PR_D1 PRI ON (PRH.PR_H_UID = PRI.PR_H_UID AND PRI.ACTV_FLAG = 'Y')
                    LEFT  JOIN MM_RX_D1 RXI ON (RXI.PR_H_UID = PRI.PR_H_UID AND RXI.PR_D1_UID = PRI.PR_D1_UID   AND RXI.ACTV_FLAG = 'Y')
                    LEFT  JOIN MM_RX_H  RXH ON (RXI.RX_H_UID = RXH.RX_H_UID AND RXH.STATUS NOT IN ('ENT','CNL') AND RXH.ACTV_FLAG = 'Y')
                    LEFT  JOIN MM_CT_D1 CTI ON (RXI.RX_H_UID = CTI.RX_H_UID AND RXI.RX_D1_UID = CTI.RX_D1_UID   AND CTI.ACTV_FLAG = 'Y')
                    LEFT  JOIN MM_CT_H  CTH ON (CTI.CT_H_UID = CTH.CT_H_UID AND CTH.STATUS NOT IN ('ENT','CNL') AND CTH.ACTV_FLAG = 'Y')
                    LEFT  JOIN MM_PO_D1 POI ON (PRI.PR_H_UID = POI.PR_H_UID AND PRI.PR_D1_UID = POI.PR_D1_UID   AND POI.ACTV_FLAG = 'Y')
                    LEFT  JOIN MM_PO_H  POH ON (POI.PO_H_UID = POH.PO_H_UID AND POH.STATUS NOT IN ('ENT','CNL') AND POH.ACTV_FLAG = 'Y')
             WHERE 1=1
               AND PRH.PR_H_UID = P_PR_H_UID
     ) A
     WHERE A.RN = 1
    ;



    IF V_RESULT IS NULL THEN
        V_RESULT := '';
    END IF;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_PROCESS_TYPE_NAME (
    P_CLIENT_CODE           IN VARCHAR2,
    P_MODULE_CODE           IN VARCHAR2,
    P_PROCESS_TYPE_CODE     IN VARCHAR2,
    P_LANGUAGE              IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary : 프로세스 명 조회
 * @return  : 프로세스 명  값
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(300);
        V_SQL    VARCHAR2(300);

BEGIN
    SELECT DECODE(NVL(P_LANGUAGE, 'X'), 'ko_KR', PROCESS_TYPE_NAME, PT.PROCESS_TYPE_NAME_EN)
    INTO   V_RESULT
    FROM   SY_PROCESS_TYPE PT
    WHERE  STATUS = 'Y'
    AND    CLIENT_CODE =  P_CLIENT_CODE --U.CLIENT_CODE
    AND    MODULE_CODE =  P_MODULE_CODE
    AND    PROCESS_TYPE_CODE = P_PROCESS_TYPE_CODE
    ;

    IF V_RESULT IS NULL THEN
        V_RESULT := '';
    END IF;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_SAFETY_RST_VALUE (
    P_RESULT_SCORE  IN NUMBER
) RETURN NUMBER IS 
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary : 공통코드 조회
 * @return  : 공통코드 값
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT NUMBER;

BEGIN

	SELECT NVL(SUM(CD.ATTR_NUMBER3), 0)
      INTO V_RESULT
      FROM SY_CM_CLASS CL
 LEFT JOIN SY_CM_CODE CD 
       	ON CL.CLASS_CODE = CD.CLASS_CODE 
       AND CL.CLIENT_CODE = CD.CLIENT_CODE 
       AND CL.COMPANY_CODE = CD.COMPANY_CODE 
       AND CD.STATUS = 'Y'
     WHERE CL.CLASS_CODE = 'SAFETY_RST_SCOPE'
       AND P_RESULT_SCORE BETWEEN ATTR_NUMBER1 AND ATTR_NUMBER2
	;
        
    IF V_RESULT IS NULL THEN
        V_RESULT := 0;
    END IF;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN 0;
END;
END;
/


CREATE OR REPLACE FUNCTION LGLPCM."FN_SPLIT" (
    P_LIST VARCHAR2,
    P_DEL  VARCHAR2
)
RETURN SPLIT_TBL PIPELINED IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        L_IDX  PLS_INTEGER;
        L_LIST VARCHAR2(32767) := P_LIST;

BEGIN
    LOOP
        L_IDX := INSTR(L_LIST, P_DEL);

        IF L_IDX > 0 THEN
            PIPE ROW(SUBSTR(L_LIST, 1, L_IDX - 1));
            L_LIST := SUBSTR(L_LIST, L_IDX + LENGTH(P_DEL));
        ELSE
            PIPE ROW(L_LIST);
            EXIT;
        END IF;
    END LOOP;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_SY_CHKLST_PATH(
  P_CLIENT_CODE VARCHAR2,
  P_CLASS_CODE  VARCHAR2
)
RETURN VARCHAR2
AS
  v_input_code VARCHAR2(4000) := P_CLASS_CODE;
  v_result_name VARCHAR2(4000) := NULL;
  v_delimiter CHAR(1) := '/';
  v_pos NUMBER;
  v_current_code VARCHAR2(4000);
BEGIN
  -- 초기값 설정
  v_result_name := NULL;

  IF LENGTH(v_input_code) > 1 then
    v_input_code := substr(v_input_code, 2);
  end IF;

  -- '/'로 코드 분리 및 명칭 조회
  WHILE INSTR(v_input_code, v_delimiter) > 0
  LOOP
    -- '/'를 찾으면 앞의 코드를 추출하여 명칭을 조회
    v_pos := INSTR(v_input_code, v_delimiter);
    v_current_code := SUBSTR(v_input_code, 1, v_pos - 1);

    BEGIN
      SELECT COALESCE(v_result_name || ' > ', '') || CHECKLIST_CLASS_NAME
      INTO v_result_name
      FROM MD_CHECKLIST_CLASS
      WHERE CLIENT_CODE = P_CLIENT_CODE
        AND CHECKLIST_CLASS_CODE = v_current_code;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        NULL;
      WHEN TOO_MANY_ROWS THEN
        NULL;
      WHEN OTHERS THEN
        NULL;
    END;



    -- 남은 코드 업데이트
    v_input_code := SUBSTR(v_input_code, v_pos + 1);
  END LOOP;

  -- 나머지 코드에 해당하는 명칭 추가
  IF v_input_code IS NOT NULL
  THEN
    BEGIN
      SELECT COALESCE(v_result_name || ' > ', '') || CHECKLIST_CLASS_NAME
      INTO v_result_name
      FROM MD_CHECKLIST_CLASS
      WHERE CLIENT_CODE = P_CLIENT_CODE
        AND CHECKLIST_CLASS_CODE = v_input_code;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        NULL;
      WHEN TOO_MANY_ROWS THEN
        NULL;
      WHEN OTHERS THEN
        NULL;
    END;

  END IF;

  IF INSTR(v_result_name, ' > ') = 1 THEN
    v_result_name := substr(v_result_name, 4);
  END IF;



  RETURN v_result_name;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_SY_LOCAL (
    P_CLIENT_CODE   IN VARCHAR2,
    P_USER_LANGUAGE IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : PYB
 * @date    : 2023.08.14
 * @summary : 그룹, 회사와 같이 Language를 관리하지 않는 로컬명칭과 영문명칭으로 구성 된 항목은
              그룹별 설정된 언어셋과 사용자 언어셋이 같으면 로컬명징을, 다르면 영문명칭을 사용 할 수 있도록
              로컬명칭 사용 여부를 판단 할 수 있도록 구분값을 리턴
 * @return  : 'Y' = 로컬명, 'N' = 영문
 ******************************************************************************************/
V_RESULT   VARCHAR2(1);
V_LANGUAGE VARCHAR2(75);

BEGIN

    BEGIN
        SELECT  NVL(CD.ATTR3, 'ko')
                INTO V_LANGUAGE
        FROM    SY_CLIENT CL LEFT OUTER JOIN
                SY_CM_CLASS  CC ON (CC.STATUS = 'Y'  AND CLASS_TYPE_CODE = 'S' AND CLASS_CODE = 'ENV_CLIENT_COUNTRY') LEFT OUTER JOIN
                SY_CM_CODE   CD ON (CC.CLASS_TYPE_CODE = CD.CLASS_TYPE_CODE AND CD.CLASS_CODE = CC.CLASS_CODE AND CD.CODE = CL.CLIENT_CODE)
        WHERE   1=1
        AND     CL.ACTV_FLAG   = 'Y'
        AND     CL.CLIENT_CODE = P_CLIENT_CODE;

        IF V_LANGUAGE IS NULL THEN
            V_LANGUAGE := 'ko';
        END IF;
    EXCEPTION
    WHEN OTHERS THEN
        V_LANGUAGE := 'ko';
    END;


    IF UPPER(V_LANGUAGE) = UPPER(P_USER_LANGUAGE)  THEN
        V_RESULT := 'Y';
    ELSE
        V_RESULT := 'N';
    END IF;

    RETURN V_RESULT;

END;


/


