CREATE OR REPLACE FUNCTION LGLPCM.FN_APV_LINE_PROCESS (
    P_CLIENT_CODE IN VARCHAR2,
    P_LINE_TYPE   IN VARCHAR2,
    P_STATUS      IN VARCHAR2,
    P_LOCALE      IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_STATUS_NAME VARCHAR2(30);

BEGIN
    -- 기안자
    IF P_LINE_TYPE = '100' THEN
        V_STATUS_NAME := FN_CO_STATUS(P_CLIENT_CODE, 'APPR_CO', P_STATUS, P_LOCALE) ;

    -- 결재자
    ELSIF P_LINE_TYPE = '200' THEN
        V_STATUS_NAME := FN_CO_STATUS(P_CLIENT_CODE, 'APPR_APV', P_STATUS, P_LOCALE) ;

    -- 합의자
    ELSIF P_LINE_TYPE = '300' THEN
        V_STATUS_NAME := FN_CO_STATUS(P_CLIENT_CODE, 'APPR_RCV', P_STATUS, P_LOCALE) ;
    END IF;

    IF V_STATUS_NAME = ' ' THEN
        V_STATUS_NAME := '-' ;
    END IF;

    RETURN V_STATUS_NAME;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_ORG_MAP_PATH_NAME(
  P_CLIENT_CODE   VARCHAR2,
  P_COMPANY_CODE  VARCHAR2,
  P_ORG_CODE      VARCHAR2,
  P_USER_LANGUAGE VARCHAR2
)
RETURN VARCHAR2
AS
  V_RESULT_NAME VARCHAR2(1000) := NULL;
BEGIN

      -- 초기값 설정
      V_RESULT_NAME := NULL;



    BEGIN

        SELECT CASE WHEN FN_SY_LOCAL (CLIENT_CODE, P_USER_LANGUAGE) = 'Y' THEN ORG_PATH_NAME
                    ELSE NVL (ORG_PATH_NAME_EN, ORG_PATH_NAME)
               END
               INTO V_RESULT_NAME
        FROM   SY_ORG_MAP
        WHERE  CLIENT_CODE  = P_CLIENT_CODE
        AND    COMPANY_CODE = P_COMPANY_CODE
        AND    ORG_CODE     = P_ORG_CODE
        AND    ACTV_FLAG    = 'Y'
        ;
    EXCEPTION WHEN NO_DATA_FOUND THEN
       V_RESULT_NAME  := '';
    WHEN OTHERS THEN
        V_RESULT_NAME := NULL;
    END;


  RETURN V_RESULT_NAME;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_USER_NAME(
    P_USER_ID IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(100);

BEGIN
    BEGIN
        SELECT FN_DECRYPT(USER_NAME, 'AES')
        INTO   V_RESULT
        FROM   SY_USER U
        WHERE  U.USER_ID = P_USER_ID;
    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := CASE WHEN P_USER_ID = 'guest' THEN 'SYSTEM'
                      ELSE P_USER_ID END;
    WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

    RETURN NVL(V_RESULT, P_USER_ID);
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_DECRYPT_MASK (
    P_ENCRYPTED_STR IN VARCHAR2,
    P_MASK_TYPE     IN VARCHAR2
)
RETURN VARCHAR2  IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary : 개인정보 암호화 필드를 마스킹 형태로 복호화 한다.
 * @param   : P_ENCRYPTED_STR : 암호화 된 문자열
              P_MASK_TYPE     : 마스킹 패턴
				                NAME   : 성명
								TELNO  : 전화번호, 휴대폰번호, 팩스번호
								EMAIL  : 이메일
								ADDR   : 상세주소
                ETC    : 전부암호화 2026-01-07 마스킹 해제
 * @return  : 마스킹 된 개인정보 복호화 값
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(4000);
        V_SIZE NUMBER(10);

BEGIN
    V_RESULT := FN_DECRYPT(P_ENCRYPTED_STR, 'AES');

    IF V_RESULT IS NULL THEN
        RETURN NULL;
    END IF;

    V_SIZE := LENGTH(V_RESULT);

    --성명
    IF P_MASK_TYPE = 'NAME' THEN
        V_RESULT := FN_MASK_NAME(V_RESULT);

    --전화번호
    ELSIF P_MASK_TYPE = 'TELNO' THEN
        V_RESULT := FN_MASK_TEL(V_RESULT);

    --이메일
    ELSIF P_MASK_TYPE = 'EMAIL' THEN
        V_RESULT := FN_MASK_EMAIL(V_RESULT);

    --주소
    ELSIF P_MASK_TYPE = 'ADDR' THEN
        V_RESULT := FN_MASK_ADDR(V_RESULT);
    
    ELSIF P_MASK_TYPE = 'ETC' THEN
        V_RESULT := V_RESULT;
    ELSE
        V_RESULT := REPLACE(LPAD(' ', LENGTH(V_RESULT), ' '), ' ', '*');
    END IF;

    RETURN V_RESULT;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_COMPANY_FROM_CODE (
    P_CLIENT_CODE IN VARCHAR2,
    P_COMPANY_CODE IN VARCHAR2,
    P_TYPE_CODE IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(4000);
        V_COMPANY_NAME VARCHAR2(300);
        V_COMPANY_NAME_EN VARCHAR2(300);
        V_BUSINESS_NUMBER VARCHAR2(300);
        V_TELEPHONE_NUMBER VARCHAR2(300);
        V_TELEPHONE_NUMBER_MASK VARCHAR2(300);
        V_FAX_NUMBER VARCHAR2(300);
        V_FAX_NUMBER_MASK VARCHAR2(300);
        V_CEO_NAME VARCHAR2(1024);
        V_CEO_NAME_MASK VARCHAR2(1024);
        V_ADDRESS1 VARCHAR2(1024);
        V_ADDRESS1_MASK VARCHAR2(1024);
        V_ADDRESS2 VARCHAR2(1024);
        V_ADDRESS2_MASK VARCHAR2(1024);
        V_ADDRESS1_EN VARCHAR2(1024);
        V_ADDRESS1_EN_MASK VARCHAR2(1024);
        V_ADDRESS2_EN VARCHAR2(1024);
        V_ADDRESS2_EN_MASK VARCHAR2(1024);
        V_ADDRESS VARCHAR2(4000);
        V_ADDRESS_MASK VARCHAR2(4000);
        V_ADDRESS_EN VARCHAR2(4000);
        V_ADDRESS_EN_MASK VARCHAR2(4000);

BEGIN
    BEGIN
        SELECT COMPANY_NAME,
            COMPANY_NAME_EN,
            BUSINESS_NUMBER,
            FN_DECRYPT(TELEPHONE_NO, 'AES') AS TELEPHONE_NUMBER,
            FN_DECRYPT_MASK(TELEPHONE_NO, 'TELNO') AS TELEPHONE_NUMBER_MASK,
            FN_DECRYPT(FAX_NO, 'AES') AS FAX_NUMBER,
            FN_DECRYPT_MASK(FAX_NO, 'TELNO') AS FAX_NUMBER_MASK,
            FN_DECRYPT(CEO_NAME, 'AES') AS CEO_NAME,
            FN_DECRYPT_MASK(CEO_NAME, 'NAME') AS CEO_NAME_MASK,
            FN_DECRYPT(ADDRESS1, 'AES') AS ADDRESS1,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_MASK,
            FN_DECRYPT(ADDRESS2, 'AES') AS ADDRESS2,
            FN_DECRYPT_MASK(ADDRESS2, 'ADDR') AS ADDRESS2_MASK,
            FN_DECRYPT(ADDRESS1_EN, 'AES') AS ADDRESS1_EN,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_EN_MASK,
            FN_DECRYPT(ADDRESS2_EN, 'AES') AS ADDRESS2_EN,
            FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR') AS ADDRESS2_EN_MASK,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            END ADDRESS,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            END ADDRESS_MASK,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT(ADDRESS1_EN, 'AES')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT(ADDRESS2_EN, 'AES')
            ELSE FN_DECRYPT(ADDRESS1_EN, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2_EN, 'AES')
            END ADDRESS_EN,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            ELSE FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            END ADDRESS_EN_MASK
        INTO
            V_COMPANY_NAME,
            V_COMPANY_NAME_EN,
            V_BUSINESS_NUMBER,
            V_TELEPHONE_NUMBER,
            V_TELEPHONE_NUMBER_MASK,
            V_FAX_NUMBER,
            V_FAX_NUMBER_MASK,
            V_CEO_NAME,
            V_CEO_NAME_MASK,
            V_ADDRESS1,
            V_ADDRESS1_MASK,
            V_ADDRESS2,
            V_ADDRESS2_MASK,
            V_ADDRESS1_EN,
            V_ADDRESS1_EN_MASK,
            V_ADDRESS2_EN,
            V_ADDRESS2_EN_MASK,
            V_ADDRESS,
            V_ADDRESS_MASK,
            V_ADDRESS_EN,
            V_ADDRESS_EN_MASK
        FROM   SY_COMPANY
        WHERE  CLIENT_CODE = P_CLIENT_CODE
        AND  COMPANY_CODE = P_COMPANY_CODE;

    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := NULL;
        WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

    IF P_TYPE_CODE = 'COMPANY_NAME' THEN
        V_RESULT := V_COMPANY_NAME;
    ELSIF P_TYPE_CODE = 'COMPANY_NAME_EN' THEN
        V_RESULT := V_COMPANY_NAME_EN;
    ELSIF P_TYPE_CODE = 'BUSINESS_NUMBER' THEN
        V_RESULT := V_BUSINESS_NUMBER;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NUMBER'THEN
        V_RESULT := V_TELEPHONE_NUMBER;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NUMBER_MASK' THEN
        V_RESULT := V_TELEPHONE_NUMBER_MASK;
    ELSIF P_TYPE_CODE = 'FAX_NUMBER' THEN
        V_RESULT := V_FAX_NUMBER;
    ELSIF P_TYPE_CODE = 'FAX_NUMBER_MASK' THEN
        V_RESULT := V_FAX_NUMBER_MASK;
    ELSIF P_TYPE_CODE = 'CEO_NAME' THEN
        V_RESULT := V_CEO_NAME;
    ELSIF P_TYPE_CODE = 'CEO_NAME_MASK' THEN
        V_RESULT := V_CEO_NAME_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1' THEN
        V_RESULT := V_ADDRESS1;
    ELSIF P_TYPE_CODE = 'ADDRESS1_MASK' THEN
        V_RESULT := V_ADDRESS1_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2' THEN
        V_RESULT := V_ADDRESS2;
    ELSIF P_TYPE_CODE = 'ADDRESS2_MASK' THEN
        V_RESULT := V_ADDRESS2_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN' THEN
        V_RESULT := V_ADDRESS1_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN_MASK' THEN
        V_RESULT := V_ADDRESS1_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN' THEN
        V_RESULT := V_ADDRESS2_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN_MASK' THEN
        V_RESULT := V_ADDRESS2_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS' THEN
        V_RESULT := V_ADDRESS;
    ELSIF P_TYPE_CODE = 'ADDRESS_MASK' THEN
        V_RESULT := V_ADDRESS_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN' THEN
        V_RESULT := V_ADDRESS_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN_MASK' THEN
        V_RESULT := V_ADDRESS_EN_MASK;
    ELSE
        V_RESULT := NULL;
    END IF;

    RETURN V_RESULT;
END;
END;

/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_CUSTOMER_FROM_CODE (
    P_CLIENT_CODE IN VARCHAR2,
    P_CUSTOMER_CODE IN VARCHAR2,
    P_TYPE_CODE IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(4000);
        V_CUSTOMER_NAME VARCHAR2(300);
        V_CUSTOMER_NAME_EN VARCHAR2(300);
        V_BUSINESS_NUMBER VARCHAR2(300);
        V_TELEPHONE_NO VARCHAR2(300);
        V_TELEPHONE_NO_MASK VARCHAR2(300);
        V_MOBILE_NO VARCHAR2(300);
        V_MOBILE_NO_MASK VARCHAR2(300);
        V_FAX_NO VARCHAR2(300);
        V_FAX_NO_MASK VARCHAR2(300);
        V_CEO_NAME VARCHAR2(1024);
        V_CEO_NAME_MASK VARCHAR2(1024);
        V_ADDRESS1 VARCHAR2(1024);
        V_ADDRESS1_MASK VARCHAR2(1024);
        V_ADDRESS2 VARCHAR2(1024);
        V_ADDRESS2_MASK VARCHAR2(1024);
        V_ADDRESS1_EN VARCHAR2(1024);
        V_ADDRESS1_EN_MASK VARCHAR2(1024);
        V_ADDRESS2_EN VARCHAR2(1024);
        V_ADDRESS2_EN_MASK VARCHAR2(1024);
        V_ADDRESS VARCHAR2(4000);
        V_ADDRESS_MASK VARCHAR2(4000);
        V_ADDRESS_EN VARCHAR2(4000);
        V_ADDRESS_EN_MASK VARCHAR2(4000);

BEGIN
    BEGIN
        SELECT CUSTOMER_NAME,
            CUSTOMER_NAME_EN,
            BUSINESS_NUMBER,
            FN_DECRYPT(TELEPHONE_NO, 'AES') AS TELEPHONE_NO,
            FN_DECRYPT_MASK(TELEPHONE_NO, 'TELNO') AS TELEPHONE_NO_MASK,
            FN_DECRYPT(MOBILE_NO, 'AES') AS MOBILE_NO,
            FN_DECRYPT_MASK(MOBILE_NO, 'TELNO') AS MOBILE_NO_MASK,
            FN_DECRYPT(FAX_NO, 'AES') AS FAX_NO,
            FN_DECRYPT_MASK(FAX_NO, 'TELNO') AS FAX_NO_MASK,
            FN_DECRYPT(CEO_NAME, 'AES') AS CEO_NAME,
            FN_DECRYPT_MASK(CEO_NAME, 'NAME') AS CEO_NAME_MASK,
            FN_DECRYPT(ADDRESS1, 'AES') AS ADDRESS1,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_MASK,
            FN_DECRYPT(ADDRESS2, 'AES') AS ADDRESS2,
            FN_DECRYPT_MASK(ADDRESS2, 'ADDR') AS ADDRESS2_MASK,
            FN_DECRYPT(ADDRESS1_EN, 'AES') AS ADDRESS1_EN,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_EN_MASK,
            FN_DECRYPT(ADDRESS2_EN, 'AES') AS ADDRESS2_EN,
            FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR') AS ADDRESS2_EN_MASK,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            END ADDRESS,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            END ADDRESS_MASK,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT(ADDRESS1_EN, 'AES')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT(ADDRESS2_EN, 'AES')
            ELSE FN_DECRYPT(ADDRESS1_EN, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2_EN, 'AES')
            END ADDRESS_EN,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            ELSE FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            END ADDRESS_EN_MASK
        INTO
            V_CUSTOMER_NAME,
            V_CUSTOMER_NAME_EN,
            V_BUSINESS_NUMBER,
            V_TELEPHONE_NO,
            V_TELEPHONE_NO_MASK,
            V_MOBILE_NO,
            V_MOBILE_NO_MASK,
            V_FAX_NO,
            V_FAX_NO_MASK,
            V_CEO_NAME,
            V_CEO_NAME_MASK,
            V_ADDRESS1,
            V_ADDRESS1_MASK,
            V_ADDRESS2,
            V_ADDRESS2_MASK,
            V_ADDRESS1_EN,
            V_ADDRESS1_EN_MASK,
            V_ADDRESS2_EN,
            V_ADDRESS2_EN_MASK,
            V_ADDRESS,
            V_ADDRESS_MASK,
            V_ADDRESS_EN,
            V_ADDRESS_EN_MASK
        FROM   MD_CUSTOMER
        WHERE  CLIENT_CODE = P_CLIENT_CODE
        AND  CUSTOMER_CODE = P_CUSTOMER_CODE;

    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := NULL;
    END;

    IF P_TYPE_CODE = 'CUSTOMER_NAME' THEN
        V_RESULT := V_CUSTOMER_NAME;
    ELSIF P_TYPE_CODE = 'CUSTOMER_NAME_EN' THEN
        V_RESULT := V_CUSTOMER_NAME_EN;
    ELSIF P_TYPE_CODE = 'BUSINESS_NUMBER' THEN
        V_RESULT := V_BUSINESS_NUMBER;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NO'THEN
        V_RESULT := V_TELEPHONE_NO;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NO_MASK' THEN
        V_RESULT := V_TELEPHONE_NO_MASK;
    ELSIF P_TYPE_CODE = 'MOBILE_NO' THEN
        V_RESULT := V_MOBILE_NO;
    ELSIF P_TYPE_CODE = 'MOBILE_NO_MASK' THEN
        V_RESULT := V_MOBILE_NO_MASK;
    ELSIF P_TYPE_CODE = 'FAX_NO' THEN
        V_RESULT := V_FAX_NO;
    ELSIF P_TYPE_CODE = 'FAX_NO_MASK' THEN
        V_RESULT := V_FAX_NO_MASK;
    ELSIF P_TYPE_CODE = 'CEO_NAME' THEN
        V_RESULT := V_CEO_NAME;
    ELSIF P_TYPE_CODE = 'CEO_NAME_MASK' THEN
        V_RESULT := V_CEO_NAME_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1' THEN
        V_RESULT := V_ADDRESS1;
    ELSIF P_TYPE_CODE = 'ADDRESS1_MASK' THEN
        V_RESULT := V_ADDRESS1_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2' THEN
        V_RESULT := V_ADDRESS2;
    ELSIF P_TYPE_CODE = 'ADDRESS2_MASK' THEN
        V_RESULT := V_ADDRESS2_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN' THEN
        V_RESULT := V_ADDRESS1_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN_MASK' THEN
        V_RESULT := V_ADDRESS1_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN' THEN
        V_RESULT := V_ADDRESS2_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN_MASK' THEN
        V_RESULT := V_ADDRESS2_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS' THEN
        V_RESULT := V_ADDRESS;
    ELSIF P_TYPE_CODE = 'ADDRESS_MASK' THEN
        V_RESULT := V_ADDRESS_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN' THEN
        V_RESULT := V_ADDRESS_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN_MASK' THEN
        V_RESULT := V_ADDRESS_EN_MASK;
    ELSE
        V_RESULT := NULL;
    END IF;

    RETURN V_RESULT;
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_SUPPLIER_FROM_CODE (
    P_CLIENT_CODE IN VARCHAR2,
    P_SUPPLIER_CODE IN VARCHAR2,
    P_TYPE_CODE IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(4000);
        V_SUPPLIER_NAME VARCHAR2(300);
        V_SUPPLIER_NAME_EN VARCHAR2(300);
        V_BUSINESS_NUMBER VARCHAR2(300);
        V_TELEPHONE_NO VARCHAR2(300);
        V_TELEPHONE_NO_MASK VARCHAR2(300);
        V_MOBILE_NO VARCHAR2(300);
        V_MOBILE_NO_MASK VARCHAR2(300);
        V_FAX_NO VARCHAR2(300);
        V_FAX_NO_MASK VARCHAR2(300);
        V_CEO_NAME VARCHAR2(1024);
        V_CEO_NAME_MASK VARCHAR2(1024);
        V_ADDRESS1 VARCHAR2(1024);
        V_ADDRESS1_MASK VARCHAR2(1024);
        V_ADDRESS2 VARCHAR2(1024);
        V_ADDRESS2_MASK VARCHAR2(1024);
        V_ADDRESS1_EN VARCHAR2(1024);
        V_ADDRESS1_EN_MASK VARCHAR2(1024);
        V_ADDRESS2_EN VARCHAR2(1024);
        V_ADDRESS2_EN_MASK VARCHAR2(1024);
        V_ADDRESS VARCHAR2(4000);
        V_ADDRESS_MASK VARCHAR2(4000);
        V_ADDRESS_EN VARCHAR2(4000);
        V_ADDRESS_EN_MASK VARCHAR2(4000);
        V_COMPANY_CLASS_CODE VARCHAR2(300);

BEGIN
    BEGIN
        SELECT SUPPLIER_NAME,
            SUPPLIER_NAME_EN,
            BUSINESS_NUMBER,
            FN_DECRYPT(TELEPHONE_NO, 'AES') AS TELEPHONE_NO,
            FN_DECRYPT_MASK(TELEPHONE_NO, 'TELNO') AS TELEPHONE_NO_MASK,
            FN_DECRYPT(MOBILE_NO, 'AES') AS MOBILE_NO,
            FN_DECRYPT_MASK(MOBILE_NO, 'TELNO') AS MOBILE_NO_MASK,
            FN_DECRYPT(FAX_NO, 'AES') AS FAX_NO,
            FN_DECRYPT_MASK(FAX_NO, 'TELNO') AS FAX_NO_MASK,
            FN_DECRYPT(CEO_NAME, 'AES') AS CEO_NAME,
            FN_DECRYPT_MASK(CEO_NAME, 'NAME') AS CEO_NAME_MASK,
            FN_DECRYPT(ADDRESS1, 'AES') AS ADDRESS1,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_MASK,
            FN_DECRYPT(ADDRESS2, 'AES') AS ADDRESS2,
            FN_DECRYPT_MASK(ADDRESS2, 'ADDR') AS ADDRESS2_MASK,
            FN_DECRYPT(ADDRESS1_EN, 'AES') AS ADDRESS1_EN,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_EN_MASK,
            FN_DECRYPT(ADDRESS2_EN, 'AES') AS ADDRESS2_EN,
            FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR') AS ADDRESS2_EN_MASK,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            END ADDRESS,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            END ADDRESS_MASK,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT(ADDRESS1_EN, 'AES')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT(ADDRESS2_EN, 'AES')
            ELSE FN_DECRYPT(ADDRESS1_EN, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2_EN, 'AES')
            END ADDRESS_EN,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            ELSE FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            END ADDRESS_EN_MASK,
            COMPANY_CLASS_CODE
        INTO
            V_SUPPLIER_NAME,
            V_SUPPLIER_NAME_EN,
            V_BUSINESS_NUMBER,
            V_TELEPHONE_NO,
            V_TELEPHONE_NO_MASK,
            V_MOBILE_NO,
            V_MOBILE_NO_MASK,
            V_FAX_NO,
            V_FAX_NO_MASK,
            V_CEO_NAME,
            V_CEO_NAME_MASK,
            V_ADDRESS1,
            V_ADDRESS1_MASK,
            V_ADDRESS2,
            V_ADDRESS2_MASK,
            V_ADDRESS1_EN,
            V_ADDRESS1_EN_MASK,
            V_ADDRESS2_EN,
            V_ADDRESS2_EN_MASK,
            V_ADDRESS,
            V_ADDRESS_MASK,
            V_ADDRESS_EN,
            V_ADDRESS_EN_MASK,
            V_COMPANY_CLASS_CODE
        FROM   MD_SUPPLIER
        WHERE  CLIENT_CODE = P_CLIENT_CODE
        AND  SUPPLIER_CODE = P_SUPPLIER_CODE;

    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := NULL;
    WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

    IF P_TYPE_CODE = 'SUPPLIER_NAME' THEN
        V_RESULT := V_SUPPLIER_NAME;
    ELSIF P_TYPE_CODE = 'SUPPLIER_NAME_EN' THEN
        V_RESULT := V_SUPPLIER_NAME_EN;
    ELSIF P_TYPE_CODE = 'BUSINESS_NUMBER' THEN
        V_RESULT := V_BUSINESS_NUMBER;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NO'THEN
        V_RESULT := V_TELEPHONE_NO;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NO_MASK' THEN
        V_RESULT := V_TELEPHONE_NO_MASK;
    ELSIF P_TYPE_CODE = 'MOBILE_NO' THEN
        V_RESULT := V_MOBILE_NO;
    ELSIF P_TYPE_CODE = 'MOBILE_NO_MASK' THEN
        V_RESULT := V_MOBILE_NO_MASK;
    ELSIF P_TYPE_CODE = 'FAX_NO' THEN
        V_RESULT := V_FAX_NO;
    ELSIF P_TYPE_CODE = 'FAX_NO_MASK' THEN
        V_RESULT := V_FAX_NO_MASK;
    ELSIF P_TYPE_CODE = 'CEO_NAME' THEN
        V_RESULT := V_CEO_NAME;
    ELSIF P_TYPE_CODE = 'CEO_NAME_MASK' THEN
        V_RESULT := V_CEO_NAME_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1' THEN
        V_RESULT := V_ADDRESS1;
    ELSIF P_TYPE_CODE = 'ADDRESS1_MASK' THEN
        V_RESULT := V_ADDRESS1_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2' THEN
        V_RESULT := V_ADDRESS2;
    ELSIF P_TYPE_CODE = 'ADDRESS2_MASK' THEN
        V_RESULT := V_ADDRESS2_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN' THEN
        V_RESULT := V_ADDRESS1_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN_MASK' THEN
        V_RESULT := V_ADDRESS1_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN' THEN
        V_RESULT := V_ADDRESS2_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN_MASK' THEN
        V_RESULT := V_ADDRESS2_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS' THEN
        V_RESULT := V_ADDRESS;
    ELSIF P_TYPE_CODE = 'ADDRESS_MASK' THEN
        V_RESULT := V_ADDRESS_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN' THEN
        V_RESULT := V_ADDRESS_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN_MASK' THEN
        V_RESULT := V_ADDRESS_EN_MASK;
    ELSIF P_TYPE_CODE = 'COMPANY_CLASS_CODE' THEN
        V_RESULT := V_COMPANY_CLASS_CODE;
    ELSE
        V_RESULT := NULL;
    END IF;

    RETURN V_RESULT;
END;
END;

/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_USER_FROM_USER_ID (
    P_USER_ID IN VARCHAR2,
    P_TYPE_CODE IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : PARKJY
 * @date    :
 * @summary : 2026-01-06 텔레폰 호출시 모바일 리턴
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(4000);
        V_COMPANY_CODE VARCHAR2(300);
        V_LOGIN_ID VARCHAR2(50);
        V_USER_NAME VARCHAR2(300);
        V_USER_NAME_MASK VARCHAR2(300);
        V_TELEPHONE_NO VARCHAR2(300);
        V_TELEPHONE_NO_MASK VARCHAR2(300);
        V_MOBILE_NO VARCHAR2(300);
        V_MOBILE_NO_MASK VARCHAR2(300);
        V_FAX_NO VARCHAR2(300);
        V_FAX_NO_MASK VARCHAR2(300);
        V_EMAIL VARCHAR2(300);
        V_EMAIL_MASK VARCHAR2(300);
        V_ADDRESS1 VARCHAR2(1024);
        V_ADDRESS1_MASK VARCHAR2(1024);
        V_ADDRESS2 VARCHAR2(1024);
        V_ADDRESS2_MASK VARCHAR2(1024);
        V_ADDRESS1_EN VARCHAR2(1024);
        V_ADDRESS1_EN_MASK VARCHAR2(1024);
        V_ADDRESS2_EN VARCHAR2(1024);
        V_ADDRESS2_EN_MASK VARCHAR2(1024);
        V_ADDRESS VARCHAR2(4000);
        V_ADDRESS_MASK VARCHAR2(4000);
        V_ADDRESS_EN VARCHAR2(4000);
        V_ADDRESS_EN_MASK VARCHAR2(4000);
        V_ORG_CODE VARCHAR2(300);
        V_ORG_NAME VARCHAR2(300);
    -- LGL 추가 250919 - 직책코드, 직책명
        V_DUTY_CODE VARCHAR2(300);
        V_DUTY_NAME VARCHAR2(300);


BEGIN
    BEGIN
        SELECT
            COMPANY_CODE,
            LOGIN_ID,
            FN_DECRYPT(USER_NAME, 'AES') AS USER_NAME,
            FN_DECRYPT_MASK(USER_NAME, 'NAME') AS USER_NAME_MASK,
            FN_DECRYPT(TELEPHONE_NO, 'AES') AS TELEPHONE_NO,
            FN_DECRYPT_MASK(TELEPHONE_NO, 'TELNO') AS TELEPHONE_NO_MASK,
            FN_DECRYPT(MOBILE_NO, 'AES') AS MOBILE_NO,
            FN_DECRYPT_MASK(MOBILE_NO, 'TELNO') AS MOBILE_NO_MASK,
            FN_DECRYPT(FAX_NO, 'AES') AS FAX_NO,
            FN_DECRYPT_MASK(FAX_NO, 'TELNO') AS FAX_NO_MASK,
            FN_DECRYPT(EMAIL, 'AES') AS EMAIL,
            FN_DECRYPT_MASK(EMAIL, 'EMAIL') AS EMAIL_MASK,
            FN_DECRYPT(ADDRESS1, 'AES') AS ADDRESS1,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_MASK,
            FN_DECRYPT(ADDRESS2, 'AES') AS ADDRESS2,
            FN_DECRYPT_MASK(ADDRESS2, 'ADDR') AS ADDRESS2_MASK,
            FN_DECRYPT(ADDRESS1_EN, 'AES') AS ADDRESS1_EN,
            FN_DECRYPT_MASK(ADDRESS1, 'ADDR') AS ADDRESS1_EN_MASK,
            FN_DECRYPT(ADDRESS2_EN, 'AES') AS ADDRESS2_EN,
            FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR') AS ADDRESS2_EN_MASK,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT(ADDRESS1, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2, 'AES')||CHR(13)||ZIP_CODE
            END ADDRESS,
            CASE WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN NULL
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')
                WHEN ADDRESS1 IS NOT NULL AND ADDRESS2 IS NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||ZIP_CODE
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')
                WHEN ADDRESS1 IS NULL AND ADDRESS2 IS NOT NULL AND ZIP_CODE IS NOT NULL THEN  FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            ELSE FN_DECRYPT_MASK(ADDRESS1, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2, 'ADDR')||CHR(13)||ZIP_CODE
            END ADDRESS_MASK,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT(ADDRESS1_EN, 'AES')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT(ADDRESS2_EN, 'AES')
            ELSE FN_DECRYPT(ADDRESS1_EN, 'AES')||CHR(13)||FN_DECRYPT(ADDRESS2_EN, 'AES')
            END ADDRESS_EN,
            CASE WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NULL THEN NULL
                WHEN ADDRESS1_EN IS NOT NULL AND ADDRESS2_EN IS NULL THEN FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')
                WHEN ADDRESS1_EN IS NULL AND ADDRESS2_EN IS NOT NULL THEN FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            ELSE FN_DECRYPT_MASK(ADDRESS1_EN, 'ADDR')||CHR(13)||FN_DECRYPT_MASK(ADDRESS2_EN, 'ADDR')
            END ADDRESS_EN_MASK,
            ORG_CODE,
            (SELECT ORG_NAME FROM VW_ORG_COMPANY V WHERE V.CLIENT_CODE = SY_USER.CLIENT_CODE AND V.COMPANY_CODE = SY_USER.COMPANY_CODE AND V.ORG_CODE = SY_USER.ORG_CODE) AS ORG_NAME,
            DUTY_CODE,
            FN_CO_COMMON_CODE(CLIENT_CODE, NULL, 'G', 'DUTY_TYPE', DUTY_CODE, NULL) AS DUTY_NAME
        INTO V_COMPANY_CODE,
            V_LOGIN_ID,
            V_USER_NAME,
            V_USER_NAME_MASK,
            V_TELEPHONE_NO,
            V_TELEPHONE_NO_MASK,
            V_MOBILE_NO,
            V_MOBILE_NO_MASK,
            V_FAX_NO,
            V_FAX_NO_MASK,
            V_EMAIL,
            V_EMAIL_MASK,
            V_ADDRESS1,
            V_ADDRESS1_MASK,
            V_ADDRESS2,
            V_ADDRESS2_MASK,
            V_ADDRESS1_EN,
            V_ADDRESS1_EN_MASK,
            V_ADDRESS2_EN,
            V_ADDRESS2_EN_MASK,
            V_ADDRESS,
            V_ADDRESS_MASK,
            V_ADDRESS_EN,
            V_ADDRESS_EN_MASK,
            V_ORG_CODE,
            V_ORG_NAME,
            V_DUTY_CODE,
            V_DUTY_NAME
        FROM SY_USER
        WHERE USER_ID = P_USER_ID;

    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := NULL;
    WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

    IF P_TYPE_CODE = 'COMPANY_CODE' THEN
        V_RESULT := V_COMPANY_CODE;
    ELSIF P_TYPE_CODE = 'LOGIN_ID' THEN
        V_RESULT := V_LOGIN_ID;
    ELSIF P_TYPE_CODE = 'USER_NAME' THEN
        V_RESULT := V_USER_NAME;
    ELSIF P_TYPE_CODE = 'USER_NAME_MASK' THEN
        V_RESULT := V_USER_NAME_MASK;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NO'THEN
        V_RESULT := V_MOBILE_NO;
    ELSIF P_TYPE_CODE = 'TELEPHONE_NO_MASK' THEN
        V_RESULT := V_MOBILE_NO_MASK;
    ELSIF P_TYPE_CODE = 'MOBILE_NO' THEN
        V_RESULT := V_MOBILE_NO;
    ELSIF P_TYPE_CODE = 'MOBILE_NO_MASK' THEN
        V_RESULT := V_MOBILE_NO_MASK;
    ELSIF P_TYPE_CODE = 'FAX_NO' THEN
        V_RESULT := V_FAX_NO;
    ELSIF P_TYPE_CODE = 'FAX_NO_MASK' THEN
        V_RESULT := V_FAX_NO_MASK;
    ELSIF P_TYPE_CODE = 'EMAIL' THEN
        V_RESULT := V_EMAIL;
    ELSIF P_TYPE_CODE = 'EMAIL_MASK' THEN
        V_RESULT := V_EMAIL_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1' THEN
        V_RESULT := V_ADDRESS1;
    ELSIF P_TYPE_CODE = 'ADDRESS1_MASK' THEN
        V_RESULT := V_ADDRESS1_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2' THEN
        V_RESULT := V_ADDRESS2;
    ELSIF P_TYPE_CODE = 'ADDRESS2_MASK' THEN
        V_RESULT := V_ADDRESS2_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN' THEN
        V_RESULT := V_ADDRESS1_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS1_EN_MASK' THEN
        V_RESULT := V_ADDRESS1_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN' THEN
        V_RESULT := V_ADDRESS2_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS2_EN_MASK' THEN
        V_RESULT := V_ADDRESS2_EN_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS' THEN
        V_RESULT := V_ADDRESS;
    ELSIF P_TYPE_CODE = 'ADDRESS_MASK' THEN
        V_RESULT := V_ADDRESS_MASK;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN' THEN
        V_RESULT := V_ADDRESS_EN;
    ELSIF P_TYPE_CODE = 'ADDRESS_EN_MASK' THEN
        V_RESULT := V_ADDRESS_EN_MASK;
    ELSIF P_TYPE_CODE = 'ORG_CODE' THEN
        V_RESULT := V_ORG_CODE;
    ELSIF P_TYPE_CODE = 'ORG_NAME' THEN
        V_RESULT := V_ORG_NAME;
    ELSIF P_TYPE_CODE = 'DUTY_CODE' THEN
        V_RESULT := V_DUTY_CODE;
    ELSIF P_TYPE_CODE = 'DUTY_NAME' THEN
        V_RESULT := V_DUTY_NAME;
    ELSE
        V_RESULT := NULL;
    END IF;

    RETURN V_RESULT;
END;
END;

/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_USER_NAME_FROM_USER_ID (
    P_USER_ID IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(100);

BEGIN
    BEGIN
        SELECT FN_DECRYPT_MASK(USER_NAME, 'NAME')
        INTO   V_RESULT
        FROM   SY_USER U
        WHERE  U.USER_ID = P_USER_ID;
    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := CASE WHEN P_USER_ID = 'guest' THEN 'SYSTEM'
                      ELSE P_USER_ID END;
    WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

    RETURN NVL(V_RESULT, P_USER_ID);
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_USER_NAME_MASK(
    P_USER_ID IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(100);

BEGIN
    BEGIN
        SELECT FN_DECRYPT_MASK(USER_NAME, 'NAME')
        INTO   V_RESULT
        FROM   SY_USER U
        WHERE  U.USER_ID = P_USER_ID;
    EXCEPTION WHEN NO_DATA_FOUND THEN
        V_RESULT := CASE WHEN P_USER_ID = 'guest' THEN 'SYSTEM'
                      ELSE P_USER_ID END;
    WHEN OTHERS THEN
        V_RESULT := NULL;
    END;

    RETURN NVL(V_RESULT, P_USER_ID);
END;
END;


/


CREATE OR REPLACE FUNCTION LGLPCM.FN_CO_HISTORY (
    P_FLAG            IN VARCHAR2,
    P_SAVE_TABLE_NAME IN VARCHAR2,
    P_SAVE_TABLE_UID  IN NUMBER,
    P_STATUS          IN VARCHAR2
)
RETURN VARCHAR2 IS
/******************************************************************************************
 * @author  : M2B
 * @date    :
 * @summary :
 * @return  :
 ******************************************************************************************/
BEGIN
    DECLARE
        V_RESULT VARCHAR2(400);

BEGIN
    SELECT CASE P_FLAG WHEN 'DS' THEN HIST.DESCRIPTION
                       WHEN 'DT' THEN TO_CHAR(HIST.MOD_DATE, 'YYYY-MM-DD')
                       WHEN 'ID' THEN HIST.MOD_ID
                       WHEN 'NM' THEN FN_CO_USER_NAME_FROM_USER_ID(HIST.MOD_ID)
                       WHEN 'SS' THEN TO_CHAR(HIST.MOD_DATE, 'YYYY-MM-DD HH24:MI:SS') END
     INTO  V_RESULT
     FROM  (SELECT DESCRIPTION,
                   STATUS,
                   MOD_DATE,
                   MOD_ID,
                   ROW_NUMBER() OVER (PARTITION BY SAVE_TABLE_UID ORDER BY TABLE_HISTORY_UID DESC) ROWNUM_,
                   TABLE_HISTORY_UID
            FROM   SY_TABLE_HISTORY
            WHERE  SAVE_TABLE_NAME = P_SAVE_TABLE_NAME
            AND    SAVE_TABLE_UID = P_SAVE_TABLE_UID
            AND    STATUS = NVL(P_STATUS, STATUS)) HIST
    WHERE  HIST.ROWNUM_ = 1;

    RETURN V_RESULT;

EXCEPTION WHEN OTHERS THEN
    RETURN '';
END;
END;
/

