        P_CLIENT_CODE VARCHAR2,
        P_SUPPLIER_CODE VARCHAR2,
        P_FROM_DATE DATE DEFAULT NULL
    ) RETURN VARCHAR2; -- 현금흐름등급

    FUNCTION FN_GET_DEBT_RATE(P_CLIENT_CODE VARCHAR2, P_SUPPLIER_CODE VARCHAR2) RETURN NUMBER; -- 부채비율
    FUNCTION FN_GET_SALES_AMOUNT(P_CLIENT_CODE VARCHAR2, P_SUPPLIER_CODE VARCHAR2) RETURN NUMBER; -- 매출액
    FUNCTION FN_GET_NET_PROFIT(P_CLIENT_CODE VARCHAR2, P_SUPPLIER_CODE VARCHAR2) RETURN NUMBER; -- 순이익
    FUNCTION FN_GET_TOTAL_AMOUNT(P_CLIENT_CODE VARCHAR2, P_SUPPLIER_CODE VARCHAR2) RETURN NUMBER; -- 총자본
    FUNCTION FN_GET_TOTAL_DEBT(P_CLIENT_CODE VARCHAR2, P_SUPPLIER_CODE VARCHAR2) RETURN NUMBER; -- 총부채
