CREATE OR REPLACE PACKAGE BODY LGLPCM.CRYPTO
IS

    FUNCTION FN_GET_KEY
    RETURN VARCHAR2 IS
    /******************************************************************************************
     * @author  :
     * @date    : 2022-04-08
     * @summary : 암호화 키를 조회한다.
     *            : DB서버 특정 디렉토리에 위치한 key 파일(MSUITE4_KEY.txt)을 조회하여
     *              이를 V_KEY_STR 값으로 복호화하여 리턴한다.
     *              (필요시 CRYPTO 패키지 소스 암호화 적용)
     *
     *            ※ 준비사항
     *            1. MSUITE4_KEY.txt 키 파일을 DB서버에 복사
     *               : 데이터 암호화에 사용할 키(matrix2b*msuite4_20220408_122400)를
     *                 별도의 키(matrix2b*msuite4_for_encrypt_key)로 한번 더 암호화한 결과 값 사용
     *                 -> ul1azNwYMg3YqAGCleZZ70G0zfWaHR1p9fvNqNsJgQapDAst2KEgpPKU7Wf1Oyx5
     *            2. 키 파일이 복사된 디렉토리에 대한 DIRECTORY OBJECT 생성
     *               ex) CREATE DIRECTORY DIR_ENC_KEY AS 'D:\app\Administrator\oradata\QADBUTF8'
     *             2025-07-11 
     ******************************************************************************************/
     /*
    BEGIN
        DECLARE
            V_ENCRYPTION_TYPE CONSTANT PLS_INTEGER := DBMS_CRYPTO.ENCRYPT_AES256 + DBMS_CRYPTO.CHAIN_CBC + DBMS_CRYPTO.PAD_PKCS5;

            V_FILE_HANDLE   UTL_FILE.FILE_TYPE;
            V_FILE_BUFFER   VARCHAR2(64);
            V_FILE_CONTENT  VARCHAR2(64);

            V_KEY_STR       VARCHAR2(32) := 'matrix2b*msuite4_for_encrypt_key';
            V_DECRYPTED_RAW RAW(1024);

    BEGIN
        V_FILE_HANDLE := UTL_FILE.FOPEN('DIR_ENC_KEY', 'MSUITE4_KEY.txt', 'R');
        UTL_FILE.GET_LINE(V_FILE_HANDLE, V_FILE_BUFFER, 64);
        V_FILE_CONTENT := V_FILE_BUFFER;
        UTL_FILE.FCLOSE(V_FILE_HANDLE);

        IF V_FILE_CONTENT IS NULL THEN
            RETURN NULL;
        END IF;

        V_DECRYPTED_RAW := DBMS_CRYPTO.DECRYPT(
            src => UTL_ENCODE.BASE64_DECODE(UTL_RAW.CAST_TO_RAW(V_FILE_CONTENT)),
            typ => V_ENCRYPTION_TYPE,
            key => UTL_I18N.STRING_TO_RAW(V_KEY_STR, 'AL32UTF8'),
            iv  => UTL_I18N.STRING_TO_RAW(SUBSTR(V_KEY_STR, 1, 16), 'AL32UTF8')
        );

        RETURN UTL_I18N.RAW_TO_CHAR(V_DECRYPTED_RAW, 'AL32UTF8');
    END;
    END FN_GET_KEY;
    */
    BEGIN
        RETURN 'matrix2b*msuite4_20220408_122400';
    END FN_GET_KEY;


    FUNCTION FN_ENCRYPT (
        P_PLAIN_STR IN VARCHAR2,
        P_ENC_TYPE  IN VARCHAR2 DEFAULT 'AES'
    ) RETURN VARCHAR2 IS
    /******************************************************************************************
     * @author  :
     * @date    : 2022-04-08
     * @summary : 평문 문자열을 암호화한다.
     ******************************************************************************************/
    BEGIN
        DECLARE
            V_ENCRYPTION_TYPE CONSTANT PLS_INTEGER := DBMS_CRYPTO.ENCRYPT_AES256 + DBMS_CRYPTO.CHAIN_CBC + DBMS_CRYPTO.PAD_PKCS5;

            V_ENCRYPTED_RAW   RAW(2000);
            V_ENCRYPTED_STR   VARCHAR2(2000);

            V_KEY_STR         VARCHAR2(32) := FN_GET_KEY();
            V_KEY_BYTES_RAW   RAW(32);

    BEGIN
        IF P_PLAIN_STR = NULL OR P_PLAIN_STR = '' THEN
            RETURN '';
        END IF;

        IF UPPER(P_ENC_TYPE) = 'AES' THEN
            V_ENCRYPTED_RAW := DBMS_CRYPTO.ENCRYPT(
                src => UTL_I18N.STRING_TO_RAW(P_PLAIN_STR, 'AL32UTF8'),
                typ => V_ENCRYPTION_TYPE,
                key => UTL_I18N.STRING_TO_RAW(V_KEY_STR, 'AL32UTF8'),
                iv  => UTL_I18N.STRING_TO_RAW(SUBSTR(V_KEY_STR, 1, 16), 'AL32UTF8')
            );

            V_ENCRYPTED_STR := UTL_RAW.CAST_TO_VARCHAR2(UTL_ENCODE.BASE64_ENCODE(V_ENCRYPTED_RAW));
        ELSE
            V_ENCRYPTED_STR := P_PLAIN_STR;
        END IF;

        RETURN V_ENCRYPTED_STR;

    EXCEPTION WHEN OTHERS THEN
        RETURN P_PLAIN_STR;
    END;
    END FN_ENCRYPT;


    FUNCTION FN_DECRYPT (
        P_ENCRYPTED_STR IN VARCHAR2,
        P_ENC_TYPE      IN VARCHAR2 DEFAULT 'AES'

    ) RETURN VARCHAR2 IS
    /******************************************************************************************
     * @author  :
     * @date    : 2022-04-08
     * @summary : 암호화 문자열을 복호화한다.
     ******************************************************************************************/
    BEGIN
        DECLARE
            V_ENCRYPTION_TYPE CONSTANT PLS_INTEGER := DBMS_CRYPTO.ENCRYPT_AES256 + DBMS_CRYPTO.CHAIN_CBC + DBMS_CRYPTO.PAD_PKCS5;

            V_DECRYPTED_RAW   RAW(2000);
            V_DECRYPTED_STR   VARCHAR2(2000);

            V_KEY_STR         VARCHAR2(32) := FN_GET_KEY();
            V_KEY_BYTES_RAW   RAW(32);

    BEGIN
        IF P_ENCRYPTED_STR = NULL OR P_ENCRYPTED_STR = '' THEN
            RETURN '';
        END IF;

        IF UPPER(P_ENC_TYPE) = 'AES' THEN
            V_DECRYPTED_RAW := DBMS_CRYPTO.DECRYPT(
                src => UTL_ENCODE.BASE64_DECODE(UTL_RAW.CAST_TO_RAW(P_ENCRYPTED_STR)),
                typ => V_ENCRYPTION_TYPE,
                key => UTL_I18N.STRING_TO_RAW(V_KEY_STR, 'AL32UTF8'),
                iv  => UTL_I18N.STRING_TO_RAW(SUBSTR(V_KEY_STR, 1, 16), 'AL32UTF8')
            );

            V_DECRYPTED_STR := UTL_I18N.RAW_TO_CHAR(V_DECRYPTED_RAW, 'AL32UTF8');
        ELSE
            V_DECRYPTED_STR := P_ENCRYPTED_STR;
        END IF;

        RETURN V_DECRYPTED_STR;

    EXCEPTION WHEN OTHERS THEN
        RETURN P_ENCRYPTED_STR;
    END;
    END FN_DECRYPT;

END CRYPTO;


/


CREATE OR REPLACE PACKAGE BODY LGLPCM.SUPPLIER_CRE IS

    -- 재무등급 조회
    FUNCTION FN_GET_GRADE(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2,
        P_FROM_DATE IN DATE DEFAULT NULL,
        P_GRADE_TYPE IN VARCHAR2
    ) RETURN VARCHAR2 IS
        V_GRADE VARCHAR2(10);
        V_EFFECTIVE_DATE DATE;
    BEGIN
        V_EFFECTIVE_DATE := NVL(P_FROM_DATE, SYSDATE - INTERVAL '2' YEAR);

        SELECT CASE P_GRADE_TYPE
                   WHEN 'CREDIT' THEN CREDIT_GRADE_CODE
                   WHEN 'CASH'   THEN CREDIT_CASHGRADE_CODE
                   ELSE NULL
               END
        INTO V_GRADE
        FROM (
            SELECT CREDIT_DATE,
                   CREDIT_GRADE_CODE,
                   CREDIT_CASHGRADE_CODE,
                   ROW_NUMBER() OVER (PARTITION BY CLIENT_CODE, SUPPLIER_CODE ORDER BY CREDIT_DATE DESC) AS RNK
            FROM MD_SUPPLIER_CRE
            WHERE CLIENT_CODE = P_CLIENT_CODE
              AND SUPPLIER_CODE = P_SUPPLIER_CODE
              AND CREDIT_DATE >= V_EFFECTIVE_DATE
        ) ST
        WHERE ST.RNK = 1;

        RETURN V_GRADE;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN NULL;
        WHEN OTHERS THEN
            RAISE;
    END FN_GET_GRADE;

    -- 신용등급 조회
    FUNCTION FN_GET_CREDIT_GRADE(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2,
        P_FROM_DATE IN DATE DEFAULT NULL
    ) RETURN VARCHAR2 IS
    BEGIN
        RETURN FN_GET_GRADE(P_CLIENT_CODE, P_SUPPLIER_CODE, P_FROM_DATE, 'CREDIT');
    END FN_GET_CREDIT_GRADE;

    -- 현금흐름등급 조회
    FUNCTION FN_GET_CASH_GRADE(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2,
        P_FROM_DATE IN DATE DEFAULT NULL
    ) RETURN VARCHAR2 IS
    BEGIN
        RETURN FN_GET_GRADE(P_CLIENT_CODE, P_SUPPLIER_CODE, P_FROM_DATE, 'CASH');
    END FN_GET_CASH_GRADE;

    -- 공통 재무 데이터 조회 함수
    FUNCTION FN_GET_LATEST_FIN(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2,
        P_TYPE IN VARCHAR2
    ) RETURN NUMBER IS
        V_RESULT_NUMBER NUMBER;
    BEGIN
        SELECT CASE P_TYPE
                   WHEN 'SALES_AMOUNT' THEN ROUND(SALES_AMOUNT) -- 매출액
                   WHEN 'DEBT_RATE'    THEN ROUND(DEBT_RATE) -- 부채비율
                   WHEN 'NET_PROFIT'   THEN ROUND(NET_PROFIT) -- 순이익
                   WHEN 'TOTAL_AMOUNT' THEN ROUND(TOTAL_AMOUNT) -- 총자본
                   WHEN 'TOTAL_DEBT'   THEN ROUND(TOTAL_DEBT) -- 총부채
                   WHEN 'TOTAL_ASSET'  THEN ROUND(TOTAL_ASSET) -- 총자산
                   ELSE NULL
               END
        INTO V_RESULT_NUMBER
        FROM (
            SELECT CLIENT_CODE,
                   SUPPLIER_CODE,
                   SALES_AMOUNT * 1000000 AS SALES_AMOUNT,
                   DEBT_RATE,
                   NET_PROFIT * 1000000 AS NET_PROFIT,
                   TOTAL_AMOUNT * 1000000 AS TOTAL_AMOUNT,
                   TOTAL_DEBT * 1000000 AS TOTAL_DEBT,
                   TOTAL_ASSET * 1000000 AS TOTAL_ASSET,
                   ROW_NUMBER() OVER (
                       PARTITION BY CLIENT_CODE, SUPPLIER_CODE
                       ORDER BY TO_NUMBER(FISCAL_YYYY) DESC
                   ) AS RNK
            FROM MD_SUPPLIER_FIN
            WHERE CLIENT_CODE = P_CLIENT_CODE
              AND SUPPLIER_CODE = P_SUPPLIER_CODE
              AND TO_NUMBER(FISCAL_YYYY) BETWEEN EXTRACT(YEAR FROM SYSDATE) - 2 AND EXTRACT(YEAR FROM SYSDATE)
        )
        WHERE RNK = 1;

        RETURN V_RESULT_NUMBER;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN NULL;
        WHEN OTHERS THEN
            RAISE;
    END FN_GET_LATEST_FIN;

    -- 부채비율 조회
    FUNCTION FN_GET_DEBT_RATE(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2
    ) RETURN NUMBER IS
    BEGIN
        RETURN FN_GET_LATEST_FIN(P_CLIENT_CODE, P_SUPPLIER_CODE, 'DEBT_RATE');
    END FN_GET_DEBT_RATE;

    -- 매출액 조회
    FUNCTION FN_GET_SALES_AMOUNT(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2
    ) RETURN NUMBER IS
    BEGIN
        RETURN FN_GET_LATEST_FIN(P_CLIENT_CODE, P_SUPPLIER_CODE, 'SALES_AMOUNT');
    END FN_GET_SALES_AMOUNT;
    
    -- 순이익 조회
    FUNCTION FN_GET_NET_PROFIT(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2
    ) RETURN NUMBER IS
    BEGIN
        RETURN FN_GET_LATEST_FIN(P_CLIENT_CODE, P_SUPPLIER_CODE, 'NET_PROFIT');
    END FN_GET_NET_PROFIT;
    
    -- 총자본 조회
    FUNCTION FN_GET_TOTAL_AMOUNT(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2
    ) RETURN NUMBER IS
    BEGIN
        RETURN FN_GET_LATEST_FIN(P_CLIENT_CODE, P_SUPPLIER_CODE, 'TOTAL_AMOUNT');
    END FN_GET_TOTAL_AMOUNT;
    
    -- 총부채 조회
    FUNCTION FN_GET_TOTAL_DEBT(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2
    ) RETURN NUMBER IS
    BEGIN
        RETURN FN_GET_LATEST_FIN(P_CLIENT_CODE, P_SUPPLIER_CODE, 'TOTAL_DEBT');
    END FN_GET_TOTAL_DEBT;
    
    -- 총자산 조회
    FUNCTION FN_GET_TOTAL_ASSET(
        P_CLIENT_CODE IN VARCHAR2,
        P_SUPPLIER_CODE IN VARCHAR2
    ) RETURN NUMBER IS
    BEGIN
        RETURN FN_GET_LATEST_FIN(P_CLIENT_CODE, P_SUPPLIER_CODE, 'TOTAL_ASSET');
    END FN_GET_TOTAL_ASSET;
    
    -- 연도급비 조회 함수
	FUNCTION FN_GET_UCT_AMOUNT(
	    P_CLIENT_CODE IN VARCHAR2,
	    P_SUPPLIER_CODE IN VARCHAR2
	) RETURN NUMBER IS
	    V_RESULT NUMBER := 0;
	BEGIN
	    SELECT NVL(SUM(CTH.CT_AMOUNT), 0)
	      INTO V_RESULT
	      FROM MM_CT_H CTH
	     WHERE CTH.ACTV_FLAG = 'Y'
	       AND CTH.CLIENT_CODE = P_CLIENT_CODE
	       AND CTH.SUPPLIER_CODE = P_SUPPLIER_CODE
	       AND CTH.PROCESS_TYPE_CODE = 'P600'
	       AND CTH.STATUS IN ('ENF', 'ODC', 'FRQ', 'FDC')
	       AND CTH.CT_DATE >= SYSDATE - INTERVAL '1' YEAR;
	
	    RETURN V_RESULT;
	EXCEPTION
	    WHEN OTHERS THEN
	        RAISE;
	END FN_GET_UCT_AMOUNT;	    
	    
    -- 담보비율 조회 함수
	FUNCTION FN_GET_GUARANTEE_RATE(
	    P_CLIENT_CODE IN VARCHAR2,
	    P_SUPPLIER_CODE IN VARCHAR2
	) RETURN NUMBER IS
		V_CREDIT_GRADE 	VARCHAR2(10); 	-- 신용등급
    	V_CASH_GRADE 	VARCHAR2(10); 	-- 현금흐름등급
    	V_DEBT_RATE 	NUMBER; 		-- 부채비율
    	V_SALES_AMOUNT 	NUMBER; 		-- 연 매출액
    	V_UCT_AMOUNT 	NUMBER; 		-- 연 도급비
    	
	    V_RESULT NUMBER := 0;
	BEGIN
		
		V_CREDIT_GRADE 	:= FN_GET_CREDIT_GRADE(P_CLIENT_CODE, P_SUPPLIER_CODE); -- 신용등급
		V_CASH_GRADE 	:= FN_GET_CASH_GRADE(P_CLIENT_CODE, P_SUPPLIER_CODE); 	-- 현금흐름등급
		V_DEBT_RATE 	:= FN_GET_DEBT_RATE(P_CLIENT_CODE, P_SUPPLIER_CODE); 	-- 부채비율
		V_SALES_AMOUNT 	:= FN_GET_SALES_AMOUNT(P_CLIENT_CODE, P_SUPPLIER_CODE); -- 연 매출액
		V_UCT_AMOUNT 	:= FN_GET_UCT_AMOUNT(P_CLIENT_CODE, P_SUPPLIER_CODE); 	-- 연 도급비
		
		/*******************************************
		 * 신용등급 : B 이상
		 * 현금흐름등급 : CF4 / CR4 이상 (C-이상)
		 * 부채비율 : 300% 미만(최근2년자료 內)
		 * 파트너사 연 매출액 > 연 도급비 이상
		 * => 모든 조건 충족 시 10% / 1개라도 미 충족 시 15%
		 *******************************************/
		IF SUBSTR(V_CREDIT_GRADE, 1, 1) IN ('A', 'B')
			AND SUBSTR(V_CASH_GRADE, 1, 1) IN ('A', 'B', 'C')
			AND V_DEBT_RATE < 300
			AND V_SALES_AMOUNT > V_UCT_AMOUNT THEN 
			
			V_RESULT := 10;
		ELSE 
			V_RESULT := 15;
		END IF;
	
	    RETURN V_RESULT;
	EXCEPTION
	    WHEN OTHERS THEN
	        RAISE;
	END FN_GET_GUARANTEE_RATE;

END SUPPLIER_CRE;
/

CREATE TABLE LGLPCM.EG_MD_ITEM_CLASS
(
  ITEM_CLASS_UID       NUMBER(22),
  CLIENT_CODE          VARCHAR2(30 BYTE),
  REG_ID               VARCHAR2(35 BYTE),
  REG_DATE             DATE,
  MOD_ID               VARCHAR2(35 BYTE),
  MOD_DATE             DATE,
  STATUS               VARCHAR2(15 BYTE),
