CREATE SEQUENCE LGLPCM.SQ_UBI_PRINT
  START WITH 1855
  MAXVALUE 999999999999999999999999999
  MINVALUE 0
  NOCYCLE
  NOCACHE
  NOORDER
  NOKEEP
  NOSCALE
  GLOBAL;

CREATE OR REPLACE VIEW LGLPCM.VW_OPER_ORG
BEQUEATH DEFINER
AS 
SELECT CLIENT_CODE,
          COMPANY_CODE,
          COMPANY_NAME ORG_NAME,
          COMPANY_NAME_EN AS ORG_NAME_EN,
          COMPANY_CODE OPER_ORG_CODE,
          COMPANY_CODE ORG_CODE,
          COMPANY_CODE ORG_PATH,
          'CP' AS ORG_TYPE_CODE,
          MOD_ID,
          MOD_DATE
     FROM LGLPCM.SY_COMPANY
    WHERE ACTV_FLAG = 'Y' AND STATUS = 'Y'
   UNION ALL
   SELECT CLIENT_CODE,
          COMPANY_CODE,
          BP_NAME ORG_NAME,
          BP_NAME_EN AS ORG_NAME_EN,
          COMPANY_CODE || BP_CODE OPER_ORG_CODE,
          BP_CODE ORG_CODE,
          COMPANY_CODE || '/' || BP_CODE ORG_PATH,
          'BP' AS ORG_TYPE_CODE,
          MOD_ID,
          MOD_DATE
     FROM LGLPCM.SY_BUSINESS_PLACE
    WHERE STATUS = 'Y'
   UNION ALL
   SELECT CLIENT_CODE,
          COMPANY_CODE,
          PLANT_NAME ORG_NAME,
          PLANT_NAME_EN AS ORG_NAME_EN,
          COMPANY_CODE || BP_CODE || PLANT_CODE OPER_ORG_CODE,
          PLANT_CODE ORG_CODE,
          COMPANY_CODE || '/' || BP_CODE || '/' || PLANT_CODE ORG_PATH,
          'PL' AS ORG_TYPE_CODE,
          MOD_ID,
          MOD_DATE
     FROM LGLPCM.SY_PLANT
    WHERE STATUS = 'Y';


CREATE OR REPLACE VIEW LGLPCM.VW_OPER_UNIT_USER
BEQUEATH DEFINER
AS 
SELECT OPUN.OPER_UNIT_UID,
          OUOU.ORG_UNIT_TYPE_CODE AS OPER_UNIT_TYPE_CODE,
          OUS.OPER_UNIT_ORG_TYPE_CODE,
          OUOU.CLIENT_CODE,
          OUOU.COMPANY_CODE,
          OU.ORG_UNIT_CODE,
          OU.ORG_UNIT_NAME,
          OU.ORG_UNIT_NAME_EN,
          OUOU.OPER_UNIT_CODE,
          OPUN.OPER_UNIT_NAME,
          OPUN.OPER_UNIT_NAME_EN,
          U.USER_UID,
          U.LOGIN_ID,
          U.USER_ID,
          OPUN.OPER_ORG_CODE,
          OPUN.OPER_ORG_PATH,
          OPUN.REG_ID,
          OPUN.REG_DATE
     FROM LGLPCM.SY_ORG_UNIT OU
          JOIN LGLPCM.SY_ORG_UNIT_OPER_UNIT OUOU
             ON (    OU.CLIENT_CODE = OUOU.CLIENT_CODE
                 AND OU.ORG_UNIT_TYPE_CODE = OUOU.ORG_UNIT_TYPE_CODE
                 AND OU.ORG_UNIT_CODE = OUOU.ORG_UNIT_CODE
                 AND OUOU.STATUS = 'Y')
          JOIN LGLPCM.SY_OPER_UNIT OPUN
             ON (    OUOU.CLIENT_CODE = OPUN.CLIENT_CODE
                 AND OUOU.COMPANY_CODE = OPUN.COMPANY_CODE
                 AND OUOU.ORG_UNIT_TYPE_CODE = OPUN.OPER_UNIT_TYPE_CODE
                 AND OUOU.OPER_UNIT_CODE = OPUN.OPER_UNIT_CODE
                 AND OPUN.STATUS = 'Y')
          JOIN LGLPCM.SY_OPER_UNIT_SET OUS
             ON (    OPUN.CLIENT_CODE = OUS.CLIENT_CODE
                 AND OPUN.COMPANY_CODE = OUS.COMPANY_CODE
                 AND OPUN.OPER_UNIT_TYPE_CODE = OUS.OPER_UNIT_TYPE_CODE
                 AND OUS.STATUS = 'Y')
          JOIN LGLPCM.SY_ORG_UNIT_USER OUU
             ON (    OU.CLIENT_CODE = OUU.CLIENT_CODE
                 AND OU.ORG_UNIT_TYPE_CODE = OUU.ORG_UNIT_TYPE_CODE
                 AND OU.ORG_UNIT_CODE = OUU.ORG_UNIT_CODE)
          JOIN LGLPCM.SY_USER U
             ON (    OUU.CLIENT_CODE = U.CLIENT_CODE
                 AND OUU.USER_ID = U.USER_ID
                 AND U.STATUS = 'Y')
    WHERE 1 = 1 AND OU.STATUS = 'Y';


CREATE OR REPLACE VIEW LGLPCM.VW_ORG_COMPANY
BEQUEATH DEFINER
AS 
SELECT CLIENT_CODE,
          COMPANY_CODE,
          COMPANY_NAME ORG_NAME,
          COMPANY_NAME_EN AS ORG_NAME_EN,
          COMPANY_CODE ORG_CODE,
          COMPANY_CODE ORG_PATH,
          COMPANY_CODE BASE_ORG_PATH,
          'CP' AS ORG_TYPE_CODE,
          STATUS,
          MOD_ID,
          MOD_DATE
     FROM LGLPCM.SY_COMPANY
    WHERE actv_flag = 'Y'
   UNION ALL
   SELECT CLIENT_CODE,
          COMPANY_CODE,
          ORG_NAME,
          ORG_NAME_EN,
          ORG_CODE,
          COMPANY_CODE || '/' || ORG_PATH,
          ORG_PATH BASE_ORG_PATH,
          ORG_TYPE_CODE,
          STATUS,
          MOD_ID,
          MOD_DATE
     FROM LGLPCM.SY_ORG
    WHERE actv_flag = 'Y';

