CREATE TABLESPACE PCM_IDX
DATAFILE 
  '+DATA' SIZE 10G AUTOEXTEND OFF
LOGGING
DEFAULT 
  NO INMEMORY
ONLINE
EXTENT MANAGEMENT LOCAL AUTOALLOCATE
BLOCKSIZE 8K
SEGMENT SPACE MANAGEMENT AUTO
FLASHBACK ON;

CREATE TABLESPACE PCM_TDE_TBL
DATAFILE 
  '+DATA' SIZE 20G AUTOEXTEND OFF
LOGGING
ENCRYPTION USING 'AES128'
DEFAULT 
  NO INMEMORY
  STORAGE (ENCRYPT)
ONLINE
EXTENT MANAGEMENT LOCAL AUTOALLOCATE
BLOCKSIZE 8K
SEGMENT SPACE MANAGEMENT AUTO
FLASHBACK ON;

CREATE TABLESPACE SYSAUX
DATAFILE 
  '+DATA' SIZE 27G AUTOEXTEND ON NEXT 10M MAXSIZE UNLIMITED
LOGGING
FORCE LOGGING
DEFAULT 
  NO INMEMORY
ONLINE
EXTENT MANAGEMENT LOCAL AUTOALLOCATE
BLOCKSIZE 8K
SEGMENT SPACE MANAGEMENT AUTO
FLASHBACK ON;

CREATE TABLESPACE SYSTEM
DATAFILE 
  '+DATA' SIZE 2G AUTOEXTEND ON NEXT 10M MAXSIZE UNLIMITED
LOGGING
FORCE LOGGING
DEFAULT 
  NO INMEMORY
ONLINE
EXTENT MANAGEMENT LOCAL AUTOALLOCATE
BLOCKSIZE 8K
FLASHBACK ON;

CREATE TEMPORARY TABLESPACE TEMP
TEMPFILE 
  '+DATA' SIZE 19835M AUTOEXTEND ON NEXT 640K MAXSIZE UNLIMITED
TABLESPACE GROUP ''
EXTENT MANAGEMENT LOCAL UNIFORM SIZE 1M
FLASHBACK ON;

CREATE UNDO TABLESPACE UNDOTBS1
DATAFILE 
  '+DATA' SIZE 5060M AUTOEXTEND ON NEXT 5M MAXSIZE UNLIMITED
ONLINE
RETENTION NOGUARANTEE
BLOCKSIZE 8K
FLASHBACK ON;

CREATE TABLESPACE USERS
DATAFILE 
  '+DATA' SIZE 75M AUTOEXTEND ON NEXT 1280K MAXSIZE UNLIMITED
LOGGING
DEFAULT 
  NO INMEMORY
ONLINE
EXTENT MANAGEMENT LOCAL AUTOALLOCATE
BLOCKSIZE 8K
SEGMENT SPACE MANAGEMENT AUTO
FLASHBACK ON;
CREATE USER ANONYMOUS
  IDENTIFIED BY <password>
  HTTP DIGEST DISABLE
  DEFAULT TABLESPACE SYSAUX
  TEMPORARY TABLESPACE TEMP
  PROFILE DEFAULT
  PASSWORD EXPIRE
  ACCOUNT LOCK;

